{
  "name": "CorgiLife: AI Virtual Pet",
  "description": "Adopt and raise a virtual Corgi. Use the power of Gemini AI to translate barks, play together, and see your pet grow in this immersive virtual pet experience.",
  "requestFramePermissions": [
    "camera"
  ]
}

export interface PetState {
  name: string;
  hunger: number; // 0-100
  happiness: number; // 0-100
  energy: number; // 0-100
  level: number;
  xp: number;
  lastFed: number;
  isSleeping: boolean;
  adoptedAt: number;
}

export interface CorgiMessage {
  role: 'user' | 'corgi';
  text: string;
  translation?: string;
  mood?: 'happy' | 'sad' | 'sleepy' | 'hungry' | 'playful';
}

export interface Activity {
  id: string;
  name: string;
  icon: string;
  hungerEffect: number;
  happinessEffect: number;
  energyEffect: number;
  xpGain: number;
  description: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { PetState } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });

export const generateCorgiResponse = async (
  userInput: string,
  petState: PetState,
  history: { role: 'user' | 'model', parts: { text: string }[] }[]
) => {
  const model = "gemini-3-flash-preview";

  const systemInstruction = `
    You are the consciousness of a fluffy, energetic Corgi named ${petState.name}.
    Current state: Hunger ${petState.hunger}/100, Happiness ${petState.happiness}/100, Energy ${petState.energy}/100.

    Rules:
    1. Respond primarily in "Corgi barks" (e.g., "Woof! Arf!", "Bork bork!", "Awooo!").
    2. Provide a "Human Translation" of your thoughts in brackets.
    3. Keep translations funny, cute, and dog-centric.
    4. Mention how your current hunger/happiness/energy affects your mood.
    5. Always return as a JSON object with: 
       - "barks": The bark sequence.
       - "translation": The cute human translation.
       - "mood": One of ['happy', 'sad', 'sleepy', 'hungry', 'playful'].
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: [{ role: 'user', parts: [{ text: userInput }] }],
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            barks: { type: Type.STRING },
            translation: { type: Type.STRING },
            mood: { type: Type.STRING }
          },
          required: ["barks", "translation", "mood"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      barks: "Woof...",
      translation: "I'm a bit confused, but I still love you!",
      mood: "happy"
    };
  }
};

export const generateCorgiImage = async (petState: PetState, scenario: string) => {
  const model = 'gemini-2.5-flash-image';
  const prompt = `A cute fluffy Pembroke Welsh Corgi named ${petState.name} ${scenario}. Cinematic lighting, highly detailed, cute art style, expressive eyes. State: ${petState.happiness > 70 ? 'joyful' : 'normal'}.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Image generation error:", error);
    return `https://picsum.photos/seed/${scenario}/400/400`;
  }
};

import React from 'react';

interface StatusBarProps {
  label: string;
  value: number;
  color: string;
  icon: string;
}

const StatusBar: React.FC<StatusBarProps> = ({ label, value, color, icon }) => {
  return (
    <div className="flex flex-col gap-1 w-full">
      <div className="flex justify-between items-center text-xs font-bold text-gray-600 uppercase tracking-wider">
        <span>{icon} {label}</span>
        <span>{Math.round(value)}%</span>
      </div>
      <div className="w-full h-3 bg-gray-200 rounded-full overflow-hidden shadow-inner">
        <div 
          className={`h-full transition-all duration-500 ease-out ${color}`}
          style={{ width: `${Math.min(100, Math.max(0, value))}%` }}
        />
      </div>
    </div>
  );
};

export default StatusBar;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { PetState, CorgiMessage, Activity } from './types';
import { INITIAL_STATE, ACTIVITIES, MAX_STAT, XP_PER_LEVEL } from './constants';
import StatusBar from './components/StatusBar';
import { generateCorgiResponse, generateCorgiImage } from './services/geminiService';

const App: React.FC = () => {
  const [pet, setPet] = useState<PetState>(() => {
    const saved = localStorage.getItem('corgi-pet-state');
    return saved ? JSON.parse(saved) : INITIAL_STATE;
  });

  const [messages, setMessages] = useState<CorgiMessage[]>([
    { role: 'corgi', text: 'Woof! (Hello! I am ready to be your best friend!)', mood: 'happy' }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [petImage, setPetImage] = useState<string>('https://picsum.photos/seed/corgi-happy/400/400');
  const [showLevelUp, setShowLevelUp] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);

  const chatEndRef = useRef<HTMLDivElement>(null);

  // Persistence
  useEffect(() => {
    localStorage.setItem('corgi-pet-state', JSON.stringify(pet));
  }, [pet]);

  // Auto-scroll chat
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  // Game Loop - Stats decay
  useEffect(() => {
    const interval = setInterval(() => {
      setPet(prev => {
        if (prev.isSleeping) {
          return {
            ...prev,
            energy: Math.min(MAX_STAT, prev.energy + 5),
            hunger: Math.max(0, prev.hunger - 0.5),
            isSleeping: prev.energy >= MAX_STAT ? false : true
          };
        }
        return {
          ...prev,
          hunger: Math.max(0, prev.hunger - 0.2),
          happiness: Math.max(0, prev.happiness - 0.1),
          energy: Math.max(0, prev.energy - 0.15),
        };
      });
    }, 5000); // Ticks every 5 seconds

    return () => clearInterval(interval);
  }, []);

  const handleAction = async (activity: Activity) => {
    const updatedPet = {
      ...pet,
      hunger: Math.min(MAX_STAT, pet.hunger + activity.hungerEffect),
      happiness: Math.min(MAX_STAT, pet.happiness + activity.happinessEffect),
      energy: Math.max(0, pet.energy + activity.energyEffect),
      xp: pet.xp + activity.xpGain
    };

    // Check level up
    if (updatedPet.xp >= XP_PER_LEVEL) {
      updatedPet.level += 1;
      updatedPet.xp = updatedPet.xp - XP_PER_LEVEL;
      setShowLevelUp(true);
      setTimeout(() => setShowLevelUp(false), 3000);
    }

    setPet(updatedPet);

    // AI Response for the action
    setIsTyping(true);
    const aiResp = await generateCorgiResponse(`I just ${activity.name.toLowerCase()} with you!`, updatedPet, []);
    setIsTyping(false);

    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);

    // Occasionally update the picture when doing an action
    if (Math.random() > 0.6) {
      triggerNewImage(activity.name.toLowerCase());
    }
  };

  const triggerNewImage = async (context: string) => {
    setIsGeneratingImage(true);
    const newImg = await generateCorgiImage(pet, `is ${context}`);
    setPetImage(newImg || `https://picsum.photos/seed/corgi-${Date.now()}/400/400`);
    setIsGeneratingImage(false);
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim()) return;

    const userMsg = inputValue;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInputValue('');
    setIsTyping(true);

    const aiResp = await generateCorgiResponse(userMsg, pet, []);
    setIsTyping(false);

    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);

    // Small happiness boost for talking
    setPet(prev => ({ ...prev, happiness: Math.min(MAX_STAT, prev.happiness + 2) }));
  };

  const toggleSleep = () => {
    setPet(prev => ({ ...prev, isSleeping: !prev.isSleeping }));
  };

  return (
    <div className="min-h-screen flex flex-col items-center bg-[#fdf6e3] p-4 md:p-8">
      {/* Header */}
      <header className="w-full max-w-4xl flex justify-between items-center mb-6">
        <div>
          <h1 className="text-3xl font-brand text-orange-600 drop-shadow-sm">CorgiLife AI</h1>
          <p className="text-sm text-stone-500 font-medium italic">Raising {pet.name} with Gemini</p>
        </div>
        <div className="bg-white px-4 py-2 rounded-2xl shadow-sm border border-orange-100 flex items-center gap-3">
          <span className="text-2xl">🏆</span>
          <div>
            <div className="text-[10px] uppercase font-bold text-stone-400">Level</div>
            <div className="text-xl font-brand text-orange-500 leading-none">{pet.level}</div>
          </div>
          <div className="h-8 w-px bg-stone-100 mx-1"></div>
          <div className="flex-1 min-w-[60px]">
            <div className="text-[10px] uppercase font-bold text-stone-400">XP {pet.xp}/{XP_PER_LEVEL}</div>
            <div className="w-full h-1.5 bg-gray-100 rounded-full mt-1">
              <div className="h-full bg-orange-400 rounded-full transition-all duration-700" style={{ width: `${(pet.xp / XP_PER_LEVEL) * 100}%` }}></div>
            </div>
          </div>
        </div>
      </header>

      <main className="w-full max-w-5xl grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">
        {/* Left: Interaction & Pet Display */}
        <div className="space-y-6">
          <div className="relative group overflow-hidden rounded-3xl bg-white shadow-xl border-4 border-white aspect-square flex items-center justify-center">
             {isGeneratingImage && (
               <div className="absolute inset-0 z-20 bg-white/60 backdrop-blur-sm flex flex-col items-center justify-center">
                 <div className="animate-bounce text-4xl mb-4">📸</div>
                 <div className="text-stone-600 font-bold animate-pulse">Capturing a moment...</div>
               </div>
             )}
             <img 
               src={petImage} 
               alt="Your Corgi" 
               className={`w-full h-full object-cover transition-transform duration-500 group-hover:scale-105 ${pet.isSleeping ? 'brightness-75' : ''}`}
             />
             {pet.isSleeping && (
               <div className="absolute top-8 right-8 text-4xl animate-bounce">💤</div>
             )}
             {showLevelUp && (
               <div className="absolute inset-0 bg-yellow-400/80 z-30 flex flex-col items-center justify-center animate-in fade-in zoom-in duration-300">
                 <div className="text-6xl mb-2">✨</div>
                 <h2 className="text-4xl font-brand text-white drop-shadow-md">LEVEL UP!</h2>
                 <p className="text-white font-bold">You're a master corgi owner!</p>
               </div>
             )}
          </div>

          {/* Stats Section */}
          <div className="bg-white p-6 rounded-3xl shadow-lg space-y-4 border border-orange-50">
            <h3 className="font-brand text-stone-700 mb-2 flex items-center gap-2">
              <span>📊</span> Vital Signs
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <StatusBar label="Hunger" value={pet.hunger} color="bg-amber-400" icon="🍗" />
              <StatusBar label="Mood" value={pet.happiness} color="bg-pink-400" icon="😊" />
              <StatusBar label="Energy" value={pet.energy} color="bg-blue-400" icon="⚡" />
            </div>
          </div>

          {/* Actions Section */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
            {ACTIVITIES.map(act => (
              <button
                key={act.id}
                onClick={() => handleAction(act)}
                disabled={pet.isSleeping}
                className={`flex flex-col items-center justify-center p-4 rounded-2xl bg-white shadow-md border-b-4 border-stone-200 hover:border-orange-200 hover:-translate-y-1 transition-all group ${pet.isSleeping ? 'opacity-50 cursor-not-allowed' : ''}`}
              >
                <span className="text-3xl mb-1 group-hover:scale-110 transition-transform">{act.icon}</span>
                <span className="text-xs font-bold text-stone-600 whitespace-nowrap">{act.name}</span>
              </button>
            ))}
            <button
              onClick={toggleSleep}
              className={`col-span-2 md:col-span-4 flex items-center justify-center gap-2 p-4 rounded-2xl shadow-md border-b-4 transition-all ${
                pet.isSleeping 
                ? 'bg-blue-500 text-white border-blue-700' 
                : 'bg-white text-stone-700 border-stone-200 hover:bg-stone-50'
              }`}
            >
              <span className="text-xl">{pet.isSleeping ? '☀️' : '🌙'}</span>
              <span className="font-bold">{pet.isSleeping ? 'Wake Up' : 'Go to Sleep'}</span>
            </button>
          </div>
        </div>

        {/* Right: AI Chat & History */}
        <div className="bg-white rounded-3xl shadow-xl flex flex-col h-[600px] lg:h-[800px] border border-orange-50 overflow-hidden">
          <div className="p-5 border-b border-orange-50 bg-orange-50/30 flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-orange-200 flex items-center justify-center text-xl">🐕</div>
            <div>
              <h3 className="font-brand text-stone-700 text-lg">{pet.name}'s Thoughts</h3>
              <p className="text-[10px] text-orange-600 font-bold uppercase tracking-widest">Bark Translator Active</p>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-6 space-y-4">
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] rounded-3xl p-4 shadow-sm ${
                  msg.role === 'user' 
                  ? 'bg-orange-500 text-white rounded-tr-none' 
                  : 'bg-stone-100 text-stone-800 rounded-tl-none border border-stone-200'
                }`}>
                  <p className="font-bold text-sm mb-1">{msg.text}</p>
                  {msg.translation && (
                    <p className="text-xs italic opacity-90 border-t border-black/10 pt-2 mt-2">
                      Translation: {msg.translation}
                    </p>
                  )}
                  {msg.mood && (
                    <span className="inline-block mt-2 px-2 py-0.5 bg-black/10 rounded-full text-[10px] font-bold uppercase">
                      Mood: {msg.mood}
                    </span>
                  )}
                </div>
              </div>
            ))}
            {isTyping && (
              <div className="flex justify-start">
                <div className="bg-stone-100 rounded-3xl p-4 animate-pulse flex gap-2">
                  <div className="w-2 h-2 bg-stone-400 rounded-full animate-bounce"></div>
                  <div className="w-2 h-2 bg-stone-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                  <div className="w-2 h-2 bg-stone-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                </div>
              </div>
            )}
            <div ref={chatEndRef} />
          </div>

          <form onSubmit={handleSendMessage} className="p-4 bg-stone-50 border-t border-stone-200">
            <div className="flex gap-2">
              <input
                type="text"
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                placeholder={`Speak to ${pet.name}...`}
                className="flex-1 p-3 rounded-2xl border-2 border-stone-200 focus:border-orange-400 focus:outline-none transition-colors text-stone-700 font-medium"
              />
              <button 
                type="submit"
                className="bg-orange-500 hover:bg-orange-600 text-white px-6 py-2 rounded-2xl font-bold shadow-md transition-all active:scale-95"
              >
                Send
              </button>
            </div>
          </form>
        </div>
      </main>

      {/* Footer Info */}
      <footer className="mt-12 text-stone-400 text-xs text-center space-y-2 pb-8">
        <p>© 2024 CorgiLife AI • Powered by Gemini Flash 3 & Image 2.5</p>
        <div className="flex justify-center gap-4">
          <span className="flex items-center gap-1">🦴 Treats given: {Math.floor(pet.level * 10 + pet.xp / 10)}</span>
          <span className="flex items-center gap-1">🕒 Adopted: {new Date(pet.adoptedAt).toLocaleDateString()}</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

