export const generateCorgiImage = async (petState: PetState, scenario: string) => {
  const model = 'gemini-2.5-flash-image';
  const prompt = `A cute fluffy ${petState.color} ${petState.breed} named ${petState.name}. It is ${petState.startAge} months old (puppy appearance). Current activity: ${scenario}. Cinematic lighting, highly detailed, professional pet photography style, expressive eyes. Atmosphere: ${petState.happiness > 70 ? 'sunny and joyful' : 'cozy and calm'}.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Image generation error:", error);
    return `https://picsum.photos/seed/${scenario}-${petState.color}/400/400`;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { PetState, CorgiMessage, Activity } from './types';
import { INITIAL_STATE, ACTIVITIES, MAX_STAT, XP_PER_LEVEL, BREEDS, COLORS } from './constants';
import StatusBar from './components/StatusBar';
import { generateCorgiResponse, generateCorgiImage } from './services/geminiService';

const App: React.FC = () => {
  const [pet, setPet] = useState<PetState>(() => {
    const saved = localStorage.getItem('corgi-pet-state-v2');
    return saved ? JSON.parse(saved) : INITIAL_STATE;
  });

  const [messages, setMessages] = useState<CorgiMessage[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [petImage, setPetImage] = useState<string>('');
  const [showLevelUp, setShowLevelUp] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);

  const chatEndRef = useRef<HTMLDivElement>(null);

  // Initial prompt if pet exists
  useEffect(() => {
    if (pet.isAdopted && messages.length === 0) {
      setMessages([{ role: 'corgi', text: `Woof! Woof! (Hi! My name is ${pet.name} and I am so excited to be your ${pet.breed} friend!)`, mood: 'happy' }]);
      triggerNewImage('sitting happily');
    }
  }, [pet.isAdopted]);

  // Persistence
  useEffect(() => {
    localStorage.setItem('corgi-pet-state-v2', JSON.stringify(pet));
  }, [pet]);

  // Auto-scroll chat
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  // Game Loop - Stats decay
  useEffect(() => {
    if (!pet.isAdopted) return;
    const interval = setInterval(() => {
      setPet(prev => {
        if (prev.isSleeping) {
          return {
            ...prev,
            energy: Math.min(MAX_STAT, prev.energy + 5),
            hunger: Math.max(0, prev.hunger - 0.5),
            isSleeping: prev.energy >= MAX_STAT ? false : true
          };
        }
        return {
          ...prev,
          hunger: Math.max(0, prev.hunger - 0.2),
          happiness: Math.max(0, prev.happiness - 0.1),
          energy: Math.max(0, prev.energy - 0.15),
        };
      });
    }, 5000);

    return () => clearInterval(interval);
  }, [pet.isAdopted]);

  const handleAdopt = () => {
    if (!pet.name.trim()) return;
    setPet(prev => ({ ...prev, isAdopted: true, adoptedAt: Date.now() }));
  };

  const handleAction = async (activity: Activity) => {
    const updatedPet = {
      ...pet,
      hunger: Math.min(MAX_STAT, pet.hunger + activity.hungerEffect),
      happiness: Math.min(MAX_STAT, pet.happiness + activity.happinessEffect),
      energy: Math.max(0, pet.energy + activity.energyEffect),
      xp: pet.xp + activity.xpGain
    };

    if (updatedPet.xp >= XP_PER_LEVEL) {
      updatedPet.level += 1;
      updatedPet.xp = updatedPet.xp - XP_PER_LEVEL;
      setShowLevelUp(true);
      setTimeout(() => setShowLevelUp(false), 3000);
    }

    setPet(updatedPet);

    setIsTyping(true);
    const aiResp = await generateCorgiResponse(`I just ${activity.name.toLowerCase()} with you!`, updatedPet, []);
    setIsTyping(false);

    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);

    if (Math.random() > 0.5) {
      triggerNewImage(activity.name.toLowerCase());
    }
  };

  const triggerNewImage = async (context: string) => {
    setIsGeneratingImage(true);
    const newImg = await generateCorgiImage(pet, `is ${context}`);
    setPetImage(newImg || `https://picsum.photos/seed/corgi-${Date.now()}/400/400`);
    setIsGeneratingImage(false);
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim()) return;

    const userMsg = inputValue;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInputValue('');
    setIsTyping(true);

    const aiResp = await generateCorgiResponse(userMsg, pet, []);
    setIsTyping(false);

    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);

    setPet(prev => ({ ...prev, happiness: Math.min(MAX_STAT, prev.happiness + 2) }));
  };

  const toggleSleep = () => {
    setPet(prev => ({ ...prev, isSleeping: !prev.isSleeping }));
  };

  // --- RENDERING ---

  if (!pet.isAdopted) {
    return (
      <div className="min-h-screen bg-[#fdf6e3] flex flex-col items-center justify-center p-6">
        <div className="max-w-xl w-full bg-white rounded-[2.5rem] shadow-2xl p-8 md:p-12 border-8 border-orange-100 animate-in fade-in zoom-in duration-500">
          <div className="text-center mb-8">
            <span className="text-6xl block mb-4">🐾</span>
            <h1 className="text-4xl font-brand text-orange-600 mb-2">Corgi Breeder</h1>
            <p className="text-stone-500 font-medium">Design your perfect fluffy companion</p>
          </div>

          <div className="space-y-6">
            <div>
              <label className="block text-xs font-bold text-stone-400 uppercase mb-2 tracking-widest">Select Breed</label>
              <select 
                value={pet.breed}
                onChange={(e) => setPet(prev => ({ ...prev, breed: e.target.value }))}
                className="w-full p-4 rounded-2xl bg-stone-50 border-2 border-stone-100 focus:border-orange-400 focus:outline-none transition-colors font-bold text-stone-700 appearance-none"
              >
                {BREEDS.map(b => <option key={b} value={b}>{b}</option>)}
              </select>
            </div>

            <div>
              <label className="block text-xs font-bold text-stone-400 uppercase mb-2 tracking-widest">Coat Color</label>
              <div className="grid grid-cols-2 gap-3">
                {COLORS.map(c => (
                  <button
                    key={c}
                    onClick={() => setPet(prev => ({ ...prev, color: c }))}
                    className={`p-3 text-xs font-bold rounded-xl border-2 transition-all ${
                      pet.color === c ? 'border-orange-400 bg-orange-50 text-orange-700' : 'border-stone-100 bg-stone-50 text-stone-500 hover:border-stone-200'
                    }`}
                  >
                    {c}
                  </button>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-2 gap-6">
              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase mb-2 tracking-widest">Start Age (Months)</label>
                <input 
                  type="number"
                  min="2"
                  max="24"
                  value={pet.startAge}
                  onChange={(e) => setPet(prev => ({ ...prev, startAge: parseInt(e.target.value) || 2 }))}
                  className="w-full p-4 rounded-2xl bg-stone-50 border-2 border-stone-100 focus:border-orange-400 focus:outline-none transition-colors font-bold text-stone-700"
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase mb-2 tracking-widest">Corgi Name</label>
                <input 
                  type="text"
                  placeholder="e.g. Potato"
                  value={pet.name}
                  onChange={(e) => setPet(prev => ({ ...prev, name: e.target.value }))}
                  className="w-full p-4 rounded-2xl bg-stone-50 border-2 border-stone-100 focus:border-orange-400 focus:outline-none transition-colors font-bold text-stone-700"
                />
              </div>
            </div>

            <button
              onClick={handleAdopt}
              disabled={!pet.name.trim()}
              className="w-full py-5 bg-orange-500 hover:bg-orange-600 text-white rounded-3xl font-brand text-xl shadow-xl hover:shadow-orange-200/50 transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Adopt My Corgi ✨
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col items-center bg-[#fdf6e3] p-4 md:p-8">
      {/* Header */}
      <header className="w-full max-w-4xl flex flex-col md:flex-row justify-between items-center gap-4 mb-8">
        <div className="text-center md:text-left">
          <h1 className="text-3xl font-brand text-orange-600 drop-shadow-sm flex items-center gap-2 justify-center md:justify-start">
            <span>🐕</span> CorgiLife
          </h1>
          <p className="text-sm text-stone-500 font-medium">
            Raising <span className="font-bold text-orange-700">{pet.name}</span>, the {pet.breed}
          </p>
        </div>

        <div className="flex items-center gap-4">
          <div className="bg-white px-4 py-2 rounded-2xl shadow-sm border border-orange-100 flex items-center gap-3">
            <span className="text-2xl">🏆</span>
            <div>
              <div className="text-[10px] uppercase font-bold text-stone-400">Level</div>
              <div className="text-xl font-brand text-orange-500 leading-none">{pet.level}</div>
            </div>
            <div className="h-8 w-px bg-stone-100 mx-1"></div>
            <div className="flex-1 min-w-[80px]">
              <div className="text-[10px] uppercase font-bold text-stone-400">XP {pet.xp}/{XP_PER_LEVEL}</div>
              <div className="w-full h-1.5 bg-gray-100 rounded-full mt-1 overflow-hidden">
                <div className="h-full bg-orange-400 transition-all duration-700" style={{ width: `${(pet.xp / XP_PER_LEVEL) * 100}%` }}></div>
              </div>
            </div>
          </div>

          <button 
            onClick={() => {
              if (confirm('Are you sure you want to re-adopt? Your current progress will be lost.')) {
                localStorage.removeItem('corgi-pet-state-v2');
                window.location.reload();
              }
            }}
            className="p-3 bg-white text-stone-400 hover:text-red-400 rounded-2xl shadow-sm border border-stone-100 transition-colors"
            title="Reset Game"
          >
            🔄
          </button>
        </div>
      </header>

      <main className="w-full max-w-6xl grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">
        {/* Left Col: Visuals & Stats */}
        <div className="space-y-6">
          <div className="relative group overflow-hidden rounded-[3rem] bg-white shadow-2xl border-8 border-white aspect-square flex items-center justify-center">
             {isGeneratingImage && (
               <div className="absolute inset-0 z-20 bg-white/80 backdrop-blur-md flex flex-col items-center justify-center">
                 <div className="animate-bounce text-5xl mb-4">✨</div>
                 <div className="text-orange-600 font-brand text-xl animate-pulse">Capturing {pet.name}'s look...</div>
               </div>
             )}
             <img 
               src={petImage || `https://picsum.photos/seed/${pet.name}/600/600`} 
               alt={pet.name} 
               className={`w-full h-full object-cover transition-transform duration-1000 group-hover:scale-105 ${pet.isSleeping ? 'brightness-75' : ''}`}
             />
             {pet.isSleeping && (
               <div className="absolute top-12 right-12 text-6xl animate-bounce">💤</div>
             )}
             {showLevelUp && (
               <div className="absolute inset-0 bg-yellow-400/90 z-30 flex flex-col items-center justify-center animate-in fade-in zoom-in duration-300">
                 <div className="text-8xl mb-4">🦴</div>
                 <h2 className="text-5xl font-brand text-white drop-shadow-lg">LEVEL UP!</h2>
                 <p className="text-white font-bold text-xl">{pet.name} is growing so fast!</p>
               </div>
             )}
          </div>

          <div className="bg-white p-8 rounded-[2.5rem] shadow-xl space-y-6 border border-orange-50">
            <h3 className="font-brand text-2xl text-stone-700 flex items-center gap-3">
              <span className="p-2 bg-orange-100 rounded-xl">📊</span> Daily Care
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <StatusBar label="Hunger" value={pet.hunger} color="bg-amber-400" icon="🍖" />
              <StatusBar label="Mood" value={pet.happiness} color="bg-pink-400" icon="💖" />
              <StatusBar label="Energy" value={pet.energy} color="bg-blue-400" icon="⚡" />
            </div>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            {ACTIVITIES.map(act => (
              <button
                key={act.id}
                onClick={() => handleAction(act)}
                disabled={pet.isSleeping}
                className={`flex flex-col items-center justify-center p-6 rounded-3xl bg-white shadow-lg border-b-8 border-stone-100 hover:border-orange-200 hover:-translate-y-1 transition-all group ${pet.isSleeping ? 'opacity-50 cursor-not-allowed grayscale' : ''}`}
