import { GoogleGenAI, Type } from "@google/genai";
import { PetState } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });

export const generateCorgiResponse = async (
  userInput: string,
  petState: PetState,
  history: { role: 'user' | 'model', parts: { text: string }[] }[]
) => {
  const model = "gemini-3-flash-preview";

  const ageDescription = petState.ageMonths < 6 ? "tiny puppy" : petState.ageMonths < 12 ? "growing puppy" : "adult dog";

  const systemInstruction = `
    You are the consciousness of a ${petState.breed} named ${petState.name}.
    Appearance: ${petState.color} coat.
    Current Age: ${petState.ageMonths} months old (${ageDescription}).
    Current state: Hunger ${petState.hunger}/100, Happiness ${petState.happiness}/100, Energy ${petState.energy}/100.

    Rules:
    1. Respond primarily in "Corgi barks" (e.g., "Woof! Arf!", "Bork bork!", "Awooo!").
    2. Provide a "Human Translation" of your thoughts in brackets.
    3. Keep translations funny, cute, and dog-centric. 
    4. Mention how your current age (${petState.ageMonths} months) affects your energy or curiosity.
    5. Always return as a JSON object with: 
       - "barks": The bark sequence.
       - "translation": The cute human translation.
       - "mood": One of ['happy', 'sad', 'sleepy', 'hungry', 'playful'].
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: [{ role: 'user', parts: [{ text: userInput }] }],
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            barks: { type: Type.STRING },
            translation: { type: Type.STRING },
            mood: { type: Type.STRING }
          },
          required: ["barks", "translation", "mood"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      barks: "Woof...",
      translation: "I'm a bit confused, but I still love you!",
      mood: "happy"
    };
  }
};

export const detectActivityFromImage = async (base64Image: string) => {
  const model = "gemini-3-flash-preview";
  const prompt = `Look at this camera frame. Is the user performing one of these actions?
  - "feed": Holding a small treat, food, or a bowl.
  - "play": Holding a ball or a toy.
  - "walk": Showing a leash, an open door, or outdoor scenery.
  - "belly-rub": Reaching out with an open hand as if to pet or scratch.
  - "none": No clear activity detected.

  Return the result as a JSON object with a single field "activity" which must be one of the keys above.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: [
        {
          parts: [
            { text: prompt },
            {
              inlineData: {
                mimeType: "image/jpeg",
                data: base64Image
              }
            }
          ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            activity: { type: Type.STRING }
          },
          required: ["activity"]
        }
      }
    });
    return JSON.parse(response.text);
  } catch (error) {
    console.error("Vision Analysis Error:", error);
    return { activity: "none" };
  }
};

export const generateCorgiImage = async (petState: PetState, scenario: string) => {
  const model = 'gemini-2.5-flash-image';

  let growthDescriptor = "puppy";
  if (petState.ageMonths >= 6 && petState.ageMonths < 12) growthDescriptor = "growing young corgi";
  if (petState.ageMonths >= 12) growthDescriptor = "adult corgi";

  const prompt = `A professional high-quality photo of a ${growthDescriptor}. 
    Breed: ${petState.breed}. 
    Coat Color: ${petState.color}. 
    Age: ${petState.ageMonths} months old. 
    Name: ${petState.name}. 
    Current activity: ${scenario}. 
    The dog is expressive, cute, and reflects its age in size and features. 
    Soft cinematic lighting, garden background, 4k resolution.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Image generation error:", error);
    return `https://picsum.photos/seed/${scenario}-${petState.color}-${petState.ageMonths}/400/400`;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { PetState, CorgiMessage, Activity } from './types';
import { INITIAL_STATE, ACTIVITIES, MAX_STAT, XP_PER_LEVEL, BREEDS, COLORS } from './constants';
import StatusBar from './components/StatusBar';
import { generateCorgiResponse, generateCorgiImage, detectActivityFromImage } from './services/geminiService';

const App: React.FC = () => {
  const [pet, setPet] = useState<PetState>(() => {
    const saved = localStorage.getItem('corgi-breeder-final-v1');
    return saved ? JSON.parse(saved) : INITIAL_STATE;
  });

  const [messages, setMessages] = useState<CorgiMessage[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [petImage, setPetImage] = useState<string>('');
  const [showLevelUp, setShowLevelUp] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);

  // AR Mode States
  const [isARMode, setIsARMode] = useState(false);
  const [visionFeedback, setVisionFeedback] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const visionInterval = useRef<number | null>(null);

  // Initial welcome message and image once adopted
  useEffect(() => {
    if (pet.isAdopted && messages.length === 0) {
      setMessages([{ 
        role: 'corgi', 
        text: `Bork bork! (Hello! My name is ${pet.name}. I'm a ${pet.ageMonths}-month-old ${pet.breed}. Let's be friends!)`, 
        mood: 'happy' 
      }]);
      triggerNewImage('excitedly greeting its new owner');
    }
  }, [pet.isAdopted]);

  // Sync state to local storage
  useEffect(() => {
    localStorage.setItem('corgi-breeder-final-v1', JSON.stringify(pet));
  }, [pet]);

  // Auto-scroll chat to latest message
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  // Game Loop: Stats decay and Sleep recovery
  useEffect(() => {
    if (!pet.isAdopted) return;
    const interval = setInterval(() => {
      setPet(prev => {
        if (prev.isSleeping) {
          const newEnergy = Math.min(MAX_STAT, prev.energy + 8);
          return {
            ...prev,
            energy: newEnergy,
            hunger: Math.max(0, prev.hunger - 0.4),
            isSleeping: newEnergy >= MAX_STAT ? false : true
          };
        }
        return {
          ...prev,
          hunger: Math.max(0, prev.hunger - 0.25),
          happiness: Math.max(0, prev.happiness - 0.15),
          energy: Math.max(0, prev.energy - 0.2),
        };
      });
    }, 5000);

    return () => clearInterval(interval);
  }, [pet.isAdopted]);

  // AR Mode Management
  useEffect(() => {
    if (isARMode) {
      startCamera();
      visionInterval.current = window.setInterval(captureAndAnalyze, 5000);
    } else {
      stopCamera();
      if (visionInterval.current) clearInterval(visionInterval.current);
    }
    return () => {
      stopCamera();
      if (visionInterval.current) clearInterval(visionInterval.current);
    };
  }, [isARMode]);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      console.error("Error accessing camera:", err);
      setIsARMode(false);
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
      videoRef.current.srcObject = null;
    }
  };

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || isAnalyzing) return;

    setIsAnalyzing(true);
    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    const base64 = canvas.toDataURL('image/jpeg', 0.7).split(',')[1];

    const result = await detectActivityFromImage(base64);
    setIsAnalyzing(false);

    if (result.activity && result.activity !== 'none') {
      const activity = ACTIVITIES.find(a => a.id === result.activity);
      if (activity) {
        setVisionFeedback(`Detected: ${activity.name}!`);
        handleAction(activity);
        setTimeout(() => setVisionFeedback(''), 3000);
      }
    }
  };

  const handleAdopt = () => {
    if (!pet.name.trim()) return;
    setPet(prev => ({ ...prev, isAdopted: true, adoptedAt: Date.now() }));
  };

  const handleAction = async (activity: Activity) => {
    const updatedPet = {
      ...pet,
      hunger: Math.min(MAX_STAT, pet.hunger + activity.hungerEffect),
      happiness: Math.min(MAX_STAT, pet.happiness + activity.happinessEffect),
      energy: Math.max(0, pet.energy + activity.energyEffect),
      xp: pet.xp + activity.xpGain
    };

    if (updatedPet.xp >= XP_PER_LEVEL) {
      updatedPet.level += 1;
      updatedPet.ageMonths += 1;
      updatedPet.xp = updatedPet.xp - XP_PER_LEVEL;
      setShowLevelUp(true);
      setTimeout(() => setShowLevelUp(false), 4000);
      triggerNewImage('growing up and looking proud');
    }

    setPet(updatedPet);

    setIsTyping(true);
    const aiResp = await generateCorgiResponse(`I just ${activity.name.toLowerCase()} with you!`, updatedPet, []);
    setIsTyping(false);

    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);

    if (!isARMode && Math.random() > 0.6) {
      triggerNewImage(activity.name.toLowerCase());
    }
  };

  const triggerNewImage = async (context: string) => {
    setIsGeneratingImage(true);
    const newImg = await generateCorgiImage(pet, `is ${context}`);
    if (newImg) setPetImage(newImg);
    setIsGeneratingImage(false);
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim()) return;

    const userMsg = inputValue;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInputValue('');
    setIsTyping(true);

    const aiResp = await generateCorgiResponse(userMsg, pet, []);
    setIsTyping(false);

    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);

    setPet(prev => ({ ...prev, happiness: Math.min(MAX_STAT, prev.happiness + 2) }));
  };

  const toggleSleep = () => {
    setPet(prev => ({ ...prev, isSleeping: !prev.isSleeping }));
    if (!pet.isSleeping) {
      triggerNewImage('sleeping peacefully in a cozy bed');
    } else {
      triggerNewImage('waking up and stretching');
    }
  };

  const getBondedTime = () => {
    const diff = Date.now() - pet.adoptedAt;
    const minutes = Math.floor(diff / (1000 * 60));
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));

    if (days > 0) return `${days} Day${days > 1 ? 's' : ''}`;
    if (hours > 0) return `${hours} Hour${hours > 1 ? 's' : ''}`;
    if (minutes > 0) return `${minutes} Min${minutes > 1 ? 's' : ''}`;
    return "Just Now";
  };

  if (!pet.isAdopted) {
    return (
      <div className="min-h-screen bg-[#fdf6e3] flex flex-col items-center justify-center p-6 bg-[url('https://www.transparenttextures.com/patterns/paws.png')]">
        <div className="max-w-2xl w-full bg-white rounded-[3.5rem] shadow-2xl p-10 md:p-14 border-[12px] border-orange-100 animate-in fade-in slide-in-from-top-4 duration-700 relative overflow-hidden">
