        text: `Bork bork! (Hello! My name is ${pet.name}. Let's be friends!)`, 
        mood: 'happy' 
      }]);
      triggerNewImage('excitedly greeting its new owner');
    }
  }, [pet.isAdopted]);

  useEffect(() => {
    localStorage.setItem('corgi-breeder-final-v1', JSON.stringify(pet));
  }, [pet]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  useEffect(() => {
    if (!pet.isAdopted) return;
    const interval = setInterval(() => {
      setPet(prev => {
        if (prev.isSleeping) {
          const newEnergy = Math.min(MAX_STAT, prev.energy + 8);
          return {
            ...prev,
            energy: newEnergy,
            hunger: Math.max(0, prev.hunger - 0.4),
            isSleeping: newEnergy >= MAX_STAT ? false : true
          };
        }
        return {
          ...prev,
          hunger: Math.max(0, prev.hunger - 0.25),
          happiness: Math.max(0, prev.happiness - 0.15),
          energy: Math.max(0, prev.energy - 0.2),
        };
      });
    }, 5000);

    return () => clearInterval(interval);
  }, [pet.isAdopted]);

  useEffect(() => {
    if (isARMode) {
      startCamera();
      visionInterval.current = window.setInterval(captureAndAnalyze, 4000);
    } else {
      stopCamera();
      if (visionInterval.current) clearInterval(visionInterval.current);
      setLastInteraction('none');
    }
    return () => {
      stopCamera();
      if (visionInterval.current) clearInterval(visionInterval.current);
    };
  }, [isARMode]);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } });
      if (videoRef.current) videoRef.current.srcObject = stream;
    } catch (err) {
      setIsARMode(false);
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
      videoRef.current.srcObject = null;
    }
  };

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || isAnalyzing || !isARMode) return;

    setIsAnalyzing(true);
    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = 400; // Low res for faster analysis
    canvas.height = (video.videoHeight / video.videoWidth) * 400;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    const base64 = canvas.toDataURL('image/jpeg', 0.6).split(',')[1];

    const result = await detectActivityFromImage(base64);
    setIsAnalyzing(false);

    if (result.confidence > 0.5) {
      if (result.interaction === lastInteraction) return; // Prevent spamming the same interaction

      setLastInteraction(result.interaction);

      if (result.interaction === 'belly_rub_hand') {
        setVisionFeedback(`He sees your hand! ${pet.name} is approaching...`);
        triggerNewImage('curiously approaching a human hand, looking up with wagging tail', true);
      } else if (result.interaction === 'belly_rub_active') {
        setVisionFeedback(`Scratches! ${pet.name} is loving the belly rub!`);
        const activity = ACTIVITIES.find(a => a.id === 'belly-rub');
        if (activity) handleAction(activity, true, 'lying on its back being happily scratched on the belly by a human hand');
      } else if (result.interaction === 'feed_hand') {
        setVisionFeedback(`Is that a treat? ${pet.name} is sniffing your hand!`);
        const activity = ACTIVITIES.find(a => a.id === 'feed');
        if (activity) handleAction(activity, true, 'happily eating a treat from a human hand');
      } else if (result.interaction === 'play_hand') {
        setVisionFeedback(`${pet.name} wants to play fetch!`);
        const activity = ACTIVITIES.find(a => a.id === 'play');
        if (activity) handleAction(activity, true, 'jumping excitedly towards a ball held by a human hand');
      }
    }
  };

  const handleAdopt = () => {
    if (!pet.name.trim()) return;
    setPet(prev => ({ ...prev, isAdopted: true, adoptedAt: Date.now() }));
  };

  const handleAction = async (activity: Activity, fromAR: boolean = false, arContext?: string) => {
    const updatedPet = {
      ...pet,
      hunger: Math.min(MAX_STAT, pet.hunger + activity.hungerEffect),
      happiness: Math.min(MAX_STAT, pet.happiness + activity.happinessEffect),
      energy: Math.max(0, pet.energy + activity.energyEffect),
      xp: pet.xp + activity.xpGain
    };

    if (updatedPet.xp >= XP_PER_LEVEL) {
      updatedPet.level += 1;
      updatedPet.ageMonths += 1;
      updatedPet.xp = updatedPet.xp - XP_PER_LEVEL;
      setShowLevelUp(true);
      setTimeout(() => setShowLevelUp(false), 4000);
      triggerNewImage('growing up and looking proud');
    }

    setPet(updatedPet);

    setIsTyping(true);
    const aiResp = await generateCorgiResponse(`I just ${activity.name.toLowerCase()} with you!`, updatedPet, []);
    setIsTyping(false);

    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);

    if (fromAR && arContext) {
      triggerNewImage(arContext, true);
    } else if (!fromAR && Math.random() > 0.6) {
      triggerNewImage(activity.name.toLowerCase());
    }
  };

  const triggerNewImage = async (context: string, isAR: boolean = false) => {
    setIsGeneratingImage(true);
    const newImg = await generateCorgiImage(pet, context, isAR);
    if (newImg) setPetImage(newImg);
    setIsGeneratingImage(false);
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim()) return;
    const userMsg = inputValue;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInputValue('');
    setIsTyping(true);
    const aiResp = await generateCorgiResponse(userMsg, pet, []);
    setIsTyping(false);
    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);
    setPet(prev => ({ ...prev, happiness: Math.min(MAX_STAT, prev.happiness + 2) }));
  };

  const toggleSleep = () => {
    setPet(prev => ({ ...prev, isSleeping: !prev.isSleeping }));
    if (!pet.isSleeping) {
      triggerNewImage('sleeping peacefully in a cozy bed');
    } else {
      triggerNewImage('waking up and stretching');
    }
  };

  const getBondedTime = () => {
    const diff = Date.now() - pet.adoptedAt;
    const minutes = Math.floor(diff / (1000 * 60));
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
    if (days > 0) return `${days} Day${days > 1 ? 's' : ''}`;
    if (hours > 0) return `${hours} Hour${hours > 1 ? 's' : ''}`;
    if (minutes > 0) return `${minutes} Min${minutes > 1 ? 's' : ''}`;
    return "Just Now";
  };

  if (!pet.isAdopted) {
    return (
      <div className="min-h-screen bg-[#fdf6e3] flex flex-col items-center justify-center p-6 bg-[url('https://www.transparenttextures.com/patterns/paws.png')]">
        <div className="max-w-2xl w-full bg-white rounded-[3.5rem] shadow-2xl p-10 md:p-14 border-[12px] border-orange-100 animate-in fade-in slide-in-from-top-4 duration-700 relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-2 bg-orange-400"></div>
          <div className="text-center mb-10">
            <span className="text-7xl block mb-6 animate-bounce">🦴</span>
            <h1 className="text-5xl font-brand text-orange-600 mb-3 tracking-tight">Electronic Breeder</h1>
            <p className="text-stone-500 font-semibold text-lg italic">Adopt and raise your unique companion</p>
          </div>
          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-2">
                <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">1. Select Breed</label>
                <select value={pet.breed} onChange={(e) => setPet(prev => ({ ...prev, breed: e.target.value }))} className="w-full p-5 rounded-2xl bg-orange-50/50 border-2 border-orange-100 focus:border-orange-400 focus:outline-none transition-all font-bold text-stone-700 appearance-none shadow-sm cursor-pointer">
                  {BREEDS.map(b => <option key={b} value={b}>{b}</option>)}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">2. Starting Month</label>
                <input type="number" min="2" max="36" value={pet.ageMonths} onChange={(e) => setPet(prev => ({ ...prev, ageMonths: parseInt(e.target.value) || 2 }))} className="w-full p-5 rounded-2xl bg-orange-50/50 border-2 border-orange-100 focus:border-orange-400 focus:outline-none transition-all font-bold text-stone-700 shadow-sm" />
              </div>
            </div>
            <div className="space-y-3">
              <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">3. Coat Appearance</label>
              <div className="grid grid-cols-3 gap-3">
                {COLORS.map(c => (
                  <button key={c} onClick={() => setPet(prev => ({ ...prev, color: c }))} className={`p-4 text-[10px] font-black rounded-2xl border-2 transition-all shadow-sm ${pet.color === c ? 'border-orange-400 bg-orange-500 text-white scale-105' : 'border-orange-100 bg-white text-stone-500 hover:border-orange-300'}`}>
                    {c}
                  </button>
                ))}
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">4. Name Your Corgi</label>
              <input type="text" placeholder="Give your friend a name..." value={pet.name} onChange={(e) => setPet(prev => ({ ...prev, name: e.target.value }))} className="w-full p-6 rounded-3xl bg-stone-50 border-2 border-stone-200 focus:border-orange-400 focus:outline-none transition-all font-brand text-2xl text-stone-800 placeholder:text-stone-300 text-center" />
            </div>
            <button onClick={handleAdopt} disabled={!pet.name.trim()} className="w-full py-6 bg-orange-500 hover:bg-orange-600 text-white rounded-[2rem] font-brand text-2xl shadow-2xl hover:shadow-orange-300/60 transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed transform hover:-translate-y-1">
              Start Raising {pet.name || 'Your Dog'} ✨
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col items-center bg-[#fdf6e3] p-4 md:p-10 relative overflow-x-hidden">
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/paws.png')]"></div>

      <header className="w-full max-w-6xl flex flex-col md:flex-row justify-between items-center gap-6 mb-12 relative z-10">
        <div className="text-center md:text-left">
          <h1 className="text-5xl font-brand text-orange-600 drop-shadow-sm flex items-center gap-3 justify-center md:justify-start">
            <span className="animate-pulse">🐾</span> {pet.name}'s World
          </h1>
          <p className="text-lg text-stone-500 font-bold mt-1">
            {pet.ageMonths} Month Old {pet.breed} • <span className="text-orange-400">{pet.color}</span>
          </p>
        </div>

        <div className="flex items-center gap-5">
          <button 
            onClick={() => setIsARMode(!isARMode)}
            className={`p-4 rounded-[2rem] font-black text-sm uppercase tracking-widest transition-all shadow-xl border-4 flex items-center gap-3 ${
              isARMode 
              ? 'bg-red-500 text-white border-red-200 animate-pulse' 
              : 'bg-white text-orange-600 border-orange-100 hover:scale-105'
            }`}
          >
            <span className="text-2xl">{isARMode ? '⏹️' : '📷'}</span>
            {isARMode ? 'Stop Vision Mode' : 'Start Vision Mode'}
          </button>

          <div className="bg-white px-6 py-4 rounded-[2rem] shadow-xl border-4 border-orange-100 flex items-center gap-5 transform hover:scale-105 transition-transform">
            <div className="text-4xl">🏅</div>
            <div>
              <div className="text-xs uppercase font-black text-stone-400 tracking-tighter">Level</div>
              <div className="text-3xl font-brand text-orange-500 leading-none">{pet.level}</div>
            </div>
            <div className="h-12 w-1 bg-stone-100 rounded-full mx-1"></div>
            <div className="flex-1 min-w-[120px]">
              <div className="flex justify-between items-end mb-2 text-xs font-black text-stone-400">XP {pet.xp}/{XP_PER_LEVEL}</div>
              <div className="w-full h-3 bg-gray-100 rounded-full overflow-hidden shadow-inner">
                <div className="h-full bg-orange-400 transition-all duration-1000 ease-out rounded-full" style={{ width: `${(pet.xp / XP_PER_LEVEL) * 100}%` }}></div>
              </div>
            </div>
          </div>
        </div>
      </header>

      <main className="w-full max-w-7xl grid grid-cols-1 lg:grid-cols-2 gap-12 items-start relative z-10">
        <div className="space-y-10">
          <div className="relative group overflow-hidden rounded-[4rem] bg-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] border-[16px] border-white aspect-square flex items-center justify-center">
             {isARMode ? (
               <div className="absolute inset-0 z-0">
                 <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover grayscale opacity-30" />
                 <canvas ref={canvasRef} className="hidden" />
                 <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-50">
                    {visionFeedback && (
                      <div className="bg-orange-500/90 text-white font-brand text-center text-3xl p-8 rounded-[3rem] animate-in zoom-in slide-in-from-bottom-10 shadow-2xl mx-10">
                        {visionFeedback}
                      </div>
                    )}
                 </div>
               </div>
             ) : (
               isGeneratingImage && (
                 <div className="absolute inset-0 z-20 bg-white/90 backdrop-blur-xl flex flex-col items-center justify-center">
                   <div className="animate-spin text-7xl mb-6">📷</div>
                   <div className="text-orange-600 font-brand text-2xl animate-pulse">Drawing {pet.name}...</div>
                 </div>
               )
             )}

             <img 
               src={petImage || `https://picsum.photos/seed/${pet.name}/800/800`} 
               alt={pet.name} 
               className={`w-full h-full object-cover transition-all duration-1000 z-10 ${pet.isSleeping ? 'brightness-50 grayscale' : ''} ${isARMode ? 'scale-90 hover:scale-95' : 'group-hover:scale-110'}`}
             />

             {pet.isSleeping && <div className="absolute top-16 right-16 text-8xl animate-bounce z-20">💤</div>}
             {showLevelUp && (
               <div className="absolute inset-0 bg-yellow-400/95 z-30 flex flex-col items-center justify-center animate-in fade-in zoom-in duration-500">
                 <div className="text-[10rem] mb-6 drop-shadow-2xl">🎂</div>
                 <h2 className="text-7xl font-brand text-white mb-4">BIRTHDAY!</h2>
                 <p className="text-white font-black text-2xl tracking-widest text-center px-10">{pet.name} IS NOW {pet.ageMonths} MONTHS OLD!</p>
               </div>
             )}
          </div>

          <div className="bg-white p-10 rounded-[3.5rem] shadow-2xl space-y-8 border-4 border-orange-50">
            <h3 className="font-brand text-3xl text-stone-700 flex items-center gap-4">🩺 Vital Signs</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
              <StatusBar label="Hunger" value={pet.hunger} color="bg-amber-400" icon="🥩" />
              <StatusBar label="Mood" value={pet.happiness} color="bg-pink-400" icon="💖" />
              <StatusBar label="Energy" value={pet.energy} color="bg-cyan-400" icon="⚡" />
            </div>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
            {ACTIVITIES.map(act => (
              <button key={act.id} onClick={() => handleAction(act)} disabled={pet.isSleeping} className={`flex flex-col items-center justify-center p-8 rounded-[2.5rem] bg-white shadow-xl border-b-[12px] border-stone-100 transition-all group ${pet.isSleeping ? 'opacity-30 grayscale cursor-not-allowed' : 'hover:-translate-y-2'}`}>
                <span className="text-5xl mb-3 group-hover:scale-125 transition-transform">{act.icon}</span>
                <span className="text-sm font-black text-stone-600 uppercase tracking-tighter text-center">{act.name}</span>
              </button>
            ))}
            <button onClick={toggleSleep} className={`col-span-2 md:col-span-4 flex items-center justify-center gap-5 p-8 rounded-[3rem] shadow-2xl border-b-[12px] transition-all ${pet.isSleeping ? 'bg-indigo-700 text-white border-indigo-900' : 'bg-white text-stone-700 border-stone-100 hover:bg-stone-50'}`}>
              <span className="text-4xl">{pet.isSleeping ? '☀️' : '🌙'}</span>
              <span className="font-brand text-2xl">{pet.isSleeping ? 'Good Morning!' : 'Time for Nap'}</span>
            </button>
          </div>
        </div>

        <div className="bg-white rounded-[4rem] shadow-2xl flex flex-col h-[700px] lg:h-[950px] border-8 border-orange-50 overflow-hidden">
          <div className="p-8 border-b-4 border-orange-50 bg-orange-50/20 flex items-center gap-6">
            <div className="w-20 h-20 rounded-3xl bg-orange-300 flex items-center justify-center text-5xl">🐕</div>
            <div>
              <h3 className="font-brand text-stone-700 text-3xl mb-2">{pet.name}'s Diary</h3>
              <p className="text-xs text-orange-600 font-black uppercase flex items-center gap-2">
                <span className="w-2 h-2 bg-green-500 rounded-full animate-ping"></span> Live Bark Translator
              </p>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-10 space-y-8 scroll-smooth scrollbar-hide">
            {isARMode && (
              <div className="p-6 bg-orange-100/50 rounded-3xl border-2 border-orange-200 mb-4 animate-in fade-in">
                <p className="text-orange-800 font-bold flex items-center gap-3">
                  <span className="text-2xl animate-spin">👀</span> Vision Active! Reach out your hand!
                </p>
                {isAnalyzing && <p className="text-orange-500 text-xs font-black uppercase mt-2 animate-pulse">Watching for hands...</p>}
              </div>
            )}
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] rounded-[2.5rem] p-7 shadow-lg relative ${msg.role === 'user' ? 'bg-orange-500 text-white rounded-tr-none' : 'bg-stone-50 text-stone-800 rounded-tl-none border-2 border-stone-100'}`}>
                  <p className="font-bold text-xl">{msg.text}</p>
                  {msg.translation && <div className="mt-6 pt-6 border-t-2 border-black/5 text-base italic font-semibold opacity-80 text-stone-600"><span className="text-[11px] block font-black uppercase tracking-[0.2em] text-orange-400 mb-2">Thoughts</span>"{msg.translation}"</div>}
                </div>
              </div>
            ))}
            {isTyping && <div className="flex justify-start"><div className="bg-stone-50 border-2 border-stone-100 rounded-full px-10 py-5 flex gap-3 animate-pulse">...</div></div>}
            <div ref={chatEndRef} />
          </div>

          <form onSubmit={handleSendMessage} className="p-8 bg-white border-t-4 border-orange-50">
            <div className="flex gap-4 items-center bg-stone-50 p-3 rounded-[2.5rem] border-4 border-stone-100 focus-within:border-orange-400 shadow-inner">
              <input type="text" value={inputValue} onChange={(e) => setInputValue(e.target.value)} placeholder={`Talk to ${pet.name}...`} className="flex-1 p-4 bg-transparent border-none focus:outline-none font-bold text-xl text-stone-700" />
              <button type="submit" className="bg-orange-500 text-white w-16 h-16 rounded-[1.5rem] flex items-center justify-center font-bold shadow-2xl hover:scale-105 active:scale-90 transition-all">🐾</button>
            </div>
          </form>
        </div>
      </main>

      <footer className="mt-20 w-full max-w-6xl grid grid-cols-2 md:grid-cols-4 gap-6 pb-20 relative z-10">
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🎂</span><span className="text-xs font-black text-stone-400 uppercase">Growth</span><p className="font-brand text-2xl text-stone-700">{pet.ageMonths} Mos</p></div>
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🧬</span><span className="text-xs font-black text-stone-400 uppercase">Breed</span><p className="font-brand text-2xl text-stone-700">{pet.breed.split(' ')[0]}</p></div>
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🏡</span><span className="text-xs font-black text-stone-400 uppercase">Bonded</span><p className="font-brand text-2xl text-stone-700">{getBondedTime()}</p></div>
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">✨</span><span className="text-xs font-black text-stone-400 uppercase">Status</span><p className="font-brand text-2xl text-green-500">THRIVING</p></div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { PetState, CorgiMessage, Activity } from './types';
import { INITIAL_STATE, ACTIVITIES, MAX_STAT, XP_PER_LEVEL, BREEDS, COLORS } from './constants';
import StatusBar from './components/StatusBar';
import { generateCorgiResponse, generateCorgiImage, detectActivityFromImage } from './services/geminiService';

const App: React.FC = () => {
  const [pet, setPet] = useState<PetState>(() => {
    const saved = localStorage.getItem('corgi-breeder-final-v1');
    return saved ? JSON.parse(saved) : INITIAL_STATE;
  });

  const [messages, setMessages] = useState<CorgiMessage[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [petImage, setPetImage] = useState<string>('');
  const [showLevelUp, setShowLevelUp] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);

  // AR Mode States
  const [isARMode, setIsARMode] = useState(false);
  const [visionFeedback, setVisionFeedback] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [lastInteraction, setLastInteraction] = useState<string>('none');

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const visionInterval = useRef<number | null>(null);

  useEffect(() => {
    if (pet.isAdopted && messages.length === 0) {
      setMessages([{ 
        role: 'corgi', 
        text: `Bork bork! (Hello! My name is ${pet.name}. Let's be friends!)`, 
        mood: 'happy' 
      }]);
      triggerNewImage('excitedly greeting its new owner');
    }
  }, [pet.isAdopted]);

  useEffect(() => {
    localStorage.setItem('corgi-breeder-final-v1', JSON.stringify(pet));
  }, [pet]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  useEffect(() => {
    if (!pet.isAdopted) return;
    const interval = setInterval(() => {
      setPet(prev => {
        if (prev.isSleeping) {
          const newEnergy = Math.min(MAX_STAT, prev.energy + 8);
          return {
            ...prev,
            energy: newEnergy,
            hunger: Math.max(0, prev.hunger - 0.4),
            isSleeping: newEnergy >= MAX_STAT ? false : true
          };
        }
        return {
          ...prev,
          hunger: Math.max(0, prev.hunger - 0.25),
          happiness: Math.max(0, prev.happiness - 0.15),
          energy: Math.max(0, prev.energy - 0.2),
        };
      });
    }, 5000);

    return () => clearInterval(interval);
  }, [pet.isAdopted]);

  useEffect(() => {
    if (isARMode) {
      startCamera();
      visionInterval.current = window.setInterval(captureAndAnalyze, 4000);
    } else {
      stopCamera();
      if (visionInterval.current) clearInterval(visionInterval.current);
      setLastInteraction('none');
    }
    return () => {
      stopCamera();
      if (visionInterval.current) clearInterval(visionInterval.current);
    };
  }, [isARMode]);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } });
      if (videoRef.current) videoRef.current.srcObject = stream;
    } catch (err) {
      setIsARMode(false);
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
      videoRef.current.srcObject = null;
    }
  };

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || isAnalyzing || !isARMode) return;

    setIsAnalyzing(true);
    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = 400; // Low res for faster analysis
    canvas.height = (video.videoHeight / video.videoWidth) * 400;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    const base64 = canvas.toDataURL('image/jpeg', 0.6).split(',')[1];

    const result = await detectActivityFromImage(base64);
    setIsAnalyzing(false);

    if (result.confidence > 0.5) {
      if (result.interaction === lastInteraction) return; // Prevent spamming the same interaction

      setLastInteraction(result.interaction);

      if (result.interaction === 'belly_rub_hand') {
        setVisionFeedback(`${pet.name} sees your hand and is curious!`);
        triggerNewImage('curiously approaching a human hand, looking up with wagging tail', true);
      } else if (result.interaction === 'belly_rub_active') {
        setVisionFeedback(`Oh yes! ${pet.name} loves the belly rub! ✨`);
        const activity = ACTIVITIES.find(a => a.id === 'belly-rub');
        if (activity) handleAction(activity, true, 'lying on its back being happily scratched on the belly by a human hand');
      } else if (result.interaction === 'feed_hand') {
        setVisionFeedback(`Nom nom! ${pet.name} is enjoying the treat! 🦴`);
        const activity = ACTIVITIES.find(a => a.id === 'feed');
        if (activity) handleAction(activity, true, 'happily eating a treat from a human hand');
      } else if (result.interaction === 'play_hand') {
        setVisionFeedback(`${pet.name} is eager to play fetch! 🎾`);
        const activity = ACTIVITIES.find(a => a.id === 'play');
        if (activity) handleAction(activity, true, 'jumping excitedly towards a ball held by a human hand');
      }
    }
  };

  const handleAdopt = () => {
    if (!pet.name.trim()) return;
    setPet(prev => ({ ...prev, isAdopted: true, adoptedAt: Date.now() }));
  };

  const handleAction = async (activity: Activity, fromAR: boolean = false, arContext?: string) => {
    const updatedPet = {
      ...pet,
      hunger: Math.min(MAX_STAT, pet.hunger + activity.hungerEffect),
      happiness: Math.min(MAX_STAT, pet.happiness + activity.happinessEffect),
      energy: Math.max(0, pet.energy + activity.energyEffect),
      xp: pet.xp + activity.xpGain
    };

    if (updatedPet.xp >= XP_PER_LEVEL) {
      updatedPet.level += 1;
      updatedPet.ageMonths += 1;
      updatedPet.xp = updatedPet.xp - XP_PER_LEVEL;
      setShowLevelUp(true);
      setTimeout(() => setShowLevelUp(false), 4000);
      triggerNewImage('growing up and looking proud');
    }

    setPet(updatedPet);

    setIsTyping(true);
    const aiResp = await generateCorgiResponse(`I just ${activity.name.toLowerCase()} with you!`, updatedPet, []);
    setIsTyping(false);

    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);

    if (fromAR && arContext) {
      triggerNewImage(arContext, true);
    } else if (!fromAR && Math.random() > 0.6) {
      triggerNewImage(activity.name.toLowerCase());
    }
  };

  const triggerNewImage = async (context: string, isAR: boolean = false) => {
    setIsGeneratingImage(true);
    const newImg = await generateCorgiImage(pet, context, isAR);
    if (newImg) setPetImage(newImg);
    setIsGeneratingImage(false);
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim()) return;
    const userMsg = inputValue;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInputValue('');
    setIsTyping(true);
    const aiResp = await generateCorgiResponse(userMsg, pet, []);
    setIsTyping(false);
    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);
    setPet(prev => ({ ...prev, happiness: Math.min(MAX_STAT, prev.happiness + 2) }));
  };

  const toggleSleep = () => {
    setPet(prev => ({ ...prev, isSleeping: !prev.isSleeping }));
    if (!pet.isSleeping) {
      triggerNewImage('sleeping peacefully in a cozy bed');
    } else {
      triggerNewImage('waking up and stretching');
    }
  };

  const getBondedTime = () => {
    const diff = Date.now() - pet.adoptedAt;
    const minutes = Math.floor(diff / (1000 * 60));
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
    if (days > 0) return `${days} Day${days > 1 ? 's' : ''}`;
    if (hours > 0) return `${hours} Hour${hours > 1 ? 's' : ''}`;
    if (minutes > 0) return `${minutes} Min${minutes > 1 ? 's' : ''}`;
    return "Just Now";
  };

  if (!pet.isAdopted) {
    return (
      <div className="min-h-screen bg-[#fdf6e3] flex flex-col items-center justify-center p-6 bg-[url('https://www.transparenttextures.com/patterns/paws.png')]">
        <div className="max-w-2xl w-full bg-white rounded-[3.5rem] shadow-2xl p-10 md:p-14 border-[12px] border-orange-100 animate-in fade-in slide-in-from-top-4 duration-700 relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-2 bg-orange-400"></div>
          <div className="text-center mb-10">
            <span className="text-7xl block mb-6 animate-bounce">🦴</span>
            <h1 className="text-5xl font-brand text-orange-600 mb-3 tracking-tight">Electronic Breeder</h1>
            <p className="text-stone-500 font-semibold text-lg italic">Adopt and raise your unique companion</p>
          </div>
          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-2">
                <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">1. Select Breed</label>
                <select value={pet.breed} onChange={(e) => setPet(prev => ({ ...prev, breed: e.target.value }))} className="w-full p-5 rounded-2xl bg-orange-50/50 border-2 border-orange-100 focus:border-orange-400 focus:outline-none transition-all font-bold text-stone-700 appearance-none shadow-sm cursor-pointer">
                  {BREEDS.map(b => <option key={b} value={b}>{b}</option>)}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">2. Starting Month</label>
                <input type="number" min="2" max="36" value={pet.ageMonths} onChange={(e) => setPet(prev => ({ ...prev, ageMonths: parseInt(e.target.value) || 2 }))} className="w-full p-5 rounded-2xl bg-orange-50/50 border-2 border-orange-100 focus:border-orange-400 focus:outline-none transition-all font-bold text-stone-700 shadow-sm" />
              </div>
            </div>
            <div className="space-y-3">
              <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">3. Coat Appearance</label>
              <div className="grid grid-cols-3 gap-3">
                {COLORS.map(c => (
                  <button key={c} onClick={() => setPet(prev => ({ ...prev, color: c }))} className={`p-4 text-[10px] font-black rounded-2xl border-2 transition-all shadow-sm ${pet.color === c ? 'border-orange-400 bg-orange-500 text-white scale-105' : 'border-orange-100 bg-white text-stone-500 hover:border-orange-300'}`}>
                    {c}
                  </button>
                ))}
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">4. Name Your Corgi</label>
              <input type="text" placeholder="Give your friend a name..." value={pet.name} onChange={(e) => setPet(prev => ({ ...prev, name: e.target.value }))} className="w-full p-6 rounded-3xl bg-stone-50 border-2 border-stone-200 focus:border-orange-400 focus:outline-none transition-all font-brand text-2xl text-stone-800 placeholder:text-stone-300 text-center" />
            </div>
            <button onClick={handleAdopt} disabled={!pet.name.trim()} className="w-full py-6 bg-orange-500 hover:bg-orange-600 text-white rounded-[2rem] font-brand text-2xl shadow-2xl hover:shadow-orange-300/60 transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed transform hover:-translate-y-1">
              Start Raising {pet.name || 'Your Dog'} ✨
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col items-center bg-[#fdf6e3] p-4 md:p-10 relative overflow-x-hidden">
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/paws.png')]"></div>

      <header className="w-full max-w-6xl flex flex-col md:flex-row justify-between items-center gap-6 mb-12 relative z-10">
        <div className="text-center md:text-left">
          <h1 className="text-5xl font-brand text-orange-600 drop-shadow-sm flex items-center gap-3 justify-center md:justify-start">
            <span className="animate-pulse">🐾</span> {pet.name}'s World
          </h1>
          <p className="text-lg text-stone-500 font-bold mt-1">
            {pet.ageMonths} Month Old {pet.breed} • <span className="text-orange-400">{pet.color}</span>
          </p>
        </div>

        <div className="flex items-center gap-5">
          <button 
            onClick={() => setIsARMode(!isARMode)}
            className={`p-4 rounded-[2rem] font-black text-sm uppercase tracking-widest transition-all shadow-xl border-4 flex items-center gap-3 ${
              isARMode 
              ? 'bg-red-500 text-white border-red-200 animate-pulse' 
              : 'bg-white text-orange-600 border-orange-100 hover:scale-105'
            }`}
          >
            <span className="text-2xl">{isARMode ? '⏹️' : '📷'}</span>
            {isARMode ? 'Stop Vision Mode' : 'Start Vision Mode'}
          </button>

          <div className="bg-white px-6 py-4 rounded-[2rem] shadow-xl border-4 border-orange-100 flex items-center gap-5 transform hover:scale-105 transition-transform">
            <div className="text-4xl">🏅</div>
            <div>
              <div className="text-xs uppercase font-black text-stone-400 tracking-tighter">Level</div>
              <div className="text-3xl font-brand text-orange-500 leading-none">{pet.level}</div>
            </div>
            <div className="h-12 w-1 bg-stone-100 rounded-full mx-1"></div>
            <div className="flex-1 min-w-[120px]">
              <div className="flex justify-between items-end mb-2 text-xs font-black text-stone-400">XP {pet.xp}/{XP_PER_LEVEL}</div>
              <div className="w-full h-3 bg-gray-100 rounded-full overflow-hidden shadow-inner">
                <div className="h-full bg-orange-400 transition-all duration-1000 ease-out rounded-full" style={{ width: `${(pet.xp / XP_PER_LEVEL) * 100}%` }}></div>
              </div>
            </div>
          </div>
        </div>
      </header>

      <main className="w-full max-w-7xl grid grid-cols-1 lg:grid-cols-2 gap-12 items-start relative z-10">
        <div className="space-y-10">
          <div className="relative group overflow-hidden rounded-[4rem] bg-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] border-[16px] border-white aspect-square flex items-center justify-center">
             {isARMode ? (
               <div className="absolute inset-0 z-0">
                 <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover grayscale opacity-30" />
                 <canvas ref={canvasRef} className="hidden" />
                 <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-50">
                    {visionFeedback && (
                      <div className="bg-orange-500/90 text-white font-brand text-center text-3xl p-8 rounded-[3rem] animate-in zoom-in slide-in-from-bottom-10 shadow-2xl mx-10">
                        {visionFeedback}
                      </div>
                    )}
                 </div>
               </div>
             ) : (
               isGeneratingImage && (
                 <div className="absolute inset-0 z-20 bg-white/90 backdrop-blur-xl flex flex-col items-center justify-center">
                   <div className="animate-spin text-7xl mb-6">📷</div>
                   <div className="text-orange-600 font-brand text-2xl animate-pulse">Drawing {pet.name}...</div>
                 </div>
               )
             )}

             <img 
               src={petImage || `https://picsum.photos/seed/${pet.name}/800/800`} 
               alt={pet.name} 
               className={`w-full h-full object-cover transition-all duration-1000 z-10 ${pet.isSleeping ? 'brightness-50 grayscale' : ''} ${isARMode ? 'scale-90 hover:scale-95' : 'group-hover:scale-110'}`}
             />

             {pet.isSleeping && <div className="absolute top-16 right-16 text-8xl animate-bounce z-20">💤</div>}
             {showLevelUp && (
               <div className="absolute inset-0 bg-yellow-400/95 z-30 flex flex-col items-center justify-center animate-in fade-in zoom-in duration-500">
                 <div className="text-[10rem] mb-6 drop-shadow-2xl">🎂</div>
                 <h2 className="text-7xl font-brand text-white mb-4">BIRTHDAY!</h2>
                 <p className="text-white font-black text-2xl tracking-widest text-center px-10">{pet.name} IS NOW {pet.ageMonths} MONTHS OLD!</p>
               </div>
             )}
          </div>

          <div className="bg-white p-10 rounded-[3.5rem] shadow-2xl space-y-8 border-4 border-orange-50">
            <h3 className="font-brand text-3xl text-stone-700 flex items-center gap-4">🩺 Vital Signs</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
              <StatusBar label="Hunger" value={pet.hunger} color="bg-amber-400" icon="🥩" />
              <StatusBar label="Mood" value={pet.happiness} color="bg-pink-400" icon="💖" />
              <StatusBar label="Energy" value={pet.energy} color="bg-cyan-400" icon="⚡" />
            </div>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
            {ACTIVITIES.map(act => (
              <button key={act.id} onClick={() => handleAction(act)} disabled={pet.isSleeping} className={`flex flex-col items-center justify-center p-8 rounded-[2.5rem] bg-white shadow-xl border-b-[12px] border-stone-100 transition-all group ${pet.isSleeping ? 'opacity-30 grayscale cursor-not-allowed' : 'hover:-translate-y-2'}`}>
                <span className="text-5xl mb-3 group-hover:scale-125 transition-transform">{act.icon}</span>
                <span className="text-sm font-black text-stone-600 uppercase tracking-tighter text-center">{act.name}</span>
              </button>
            ))}
            <button onClick={toggleSleep} className={`col-span-2 md:col-span-4 flex items-center justify-center gap-5 p-8 rounded-[3rem] shadow-2xl border-b-[12px] transition-all ${pet.isSleeping ? 'bg-indigo-700 text-white border-indigo-900' : 'bg-white text-stone-700 border-stone-100 hover:bg-stone-50'}`}>
              <span className="text-4xl">{pet.isSleeping ? '☀️' : '🌙'}</span>
              <span className="font-brand text-2xl">{pet.isSleeping ? 'Good Morning!' : 'Time for Nap'}</span>
            </button>
          </div>
        </div>

        <div className="bg-white rounded-[4rem] shadow-2xl flex flex-col h-[700px] lg:h-[950px] border-8 border-orange-50 overflow-hidden">
          <div className="p-8 border-b-4 border-orange-50 bg-orange-50/20 flex items-center gap-6">
            <div className="w-20 h-20 rounded-3xl bg-orange-300 flex items-center justify-center text-5xl">🐕</div>
            <div>
              <h3 className="font-brand text-stone-700 text-3xl mb-2">{pet.name}'s Diary</h3>
              <p className="text-xs text-orange-600 font-black uppercase flex items-center gap-2">
                <span className="w-2 h-2 bg-green-500 rounded-full animate-ping"></span> Live Bark Translator
              </p>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-10 space-y-8 scroll-smooth scrollbar-hide">
            {isARMode && (
              <div className="p-6 bg-orange-100/50 rounded-3xl border-2 border-orange-200 mb-4 animate-in fade-in">
                <p className="text-orange-800 font-bold flex items-center gap-3">
                  <span className="text-2xl animate-spin">👀</span> Vision Active! Reach out your hand!
                </p>
                {isAnalyzing && <p className="text-orange-500 text-xs font-black uppercase mt-2 animate-pulse">Watching for hands...</p>}
              </div>
            )}
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] rounded-[2.5rem] p-7 shadow-lg relative ${msg.role === 'user' ? 'bg-orange-500 text-white rounded-tr-none' : 'bg-stone-50 text-stone-800 rounded-tl-none border-2 border-stone-100'}`}>
                  <p className="font-bold text-xl">{msg.text}</p>
                  {msg.translation && <div className="mt-6 pt-6 border-t-2 border-black/5 text-base italic font-semibold opacity-80 text-stone-600"><span className="text-[11px] block font-black uppercase tracking-[0.2em] text-orange-400 mb-2">Thoughts</span>"{msg.translation}"</div>}
                </div>
              </div>
            ))}
            {isTyping && <div className="flex justify-start"><div className="bg-stone-50 border-2 border-stone-100 rounded-full px-10 py-5 flex gap-3 animate-pulse">...</div></div>}
            <div ref={chatEndRef} />
          </div>

          <form onSubmit={handleSendMessage} className="p-8 bg-white border-t-4 border-orange-50">
            <div className="flex gap-4 items-center bg-stone-50 p-3 rounded-[2.5rem] border-4 border-stone-100 focus-within:border-orange-400 shadow-inner">
              <input type="text" value={inputValue} onChange={(e) => setInputValue(e.target.value)} placeholder={`Talk to ${pet.name}...`} className="flex-1 p-4 bg-transparent border-none focus:outline-none font-bold text-xl text-stone-700" />
              <button type="submit" className="bg-orange-500 text-white w-16 h-16 rounded-[1.5rem] flex items-center justify-center font-bold shadow-2xl hover:scale-105 active:scale-90 transition-all">🐾</button>
            </div>
          </form>
        </div>
      </main>

      <footer className="mt-20 w-full max-w-6xl grid grid-cols-2 md:grid-cols-4 gap-6 pb-20 relative z-10">
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🎂</span><span className="text-xs font-black text-stone-400 uppercase">Growth</span><p className="font-brand text-2xl text-stone-700">{pet.ageMonths} Mos</p></div>
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🧬</span><span className="text-xs font-black text-stone-400 uppercase">Breed</span><p className="font-brand text-2xl text-stone-700">{pet.breed.split(' ')[0]}</p></div>
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🏡</span><span className="text-xs font-black text-stone-400 uppercase">Bonded</span><p className="font-brand text-2xl text-stone-700">{getBondedTime()}</p></div>
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">✨</span><span className="text-xs font-black text-stone-400 uppercase">Status</span><p className="font-brand text-2xl text-green-500">THRIVING</p></div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { PetState, CorgiMessage, Activity } from './types';
import { INITIAL_STATE, ACTIVITIES, MAX_STAT, XP_PER_LEVEL, BREEDS, COLORS } from './constants';
import StatusBar from './components/StatusBar';
import { generateCorgiResponse, generateCorgiImage, detectActivityFromImage } from './services/geminiService';

const App: React.FC = () => {
  const [pet, setPet] = useState<PetState>(() => {
    const saved = localStorage.getItem('corgi-breeder-final-v1');
    return saved ? JSON.parse(saved) : INITIAL_STATE;
  });

  const [messages, setMessages] = useState<CorgiMessage[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [petImage, setPetImage] = useState<string>('');
  const [showLevelUp, setShowLevelUp] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);

  // AR Mode States
  const [isARMode, setIsARMode] = useState(false);
  const [visionFeedback, setVisionFeedback] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [lastInteraction, setLastInteraction] = useState<string>('none');
  const [isReacting, setIsReacting] = useState(false);
  const [particles, setParticles] = useState<{ id: number, x: number, y: number, char: string }[]>([]);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const visionInterval = useRef<number | null>(null);

  useEffect(() => {
    if (pet.isAdopted && messages.length === 0) {
      setMessages([{ 
        role: 'corgi', 
        text: `Bork bork! (Hello! My name is ${pet.name}. Let's be friends!)`, 
        mood: 'happy' 
      }]);
      triggerNewImage('excitedly greeting its new owner');
    }
  }, [pet.isAdopted]);

  useEffect(() => {
    localStorage.setItem('corgi-breeder-final-v1', JSON.stringify(pet));
  }, [pet]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  useEffect(() => {
    if (!pet.isAdopted) return;
    const interval = setInterval(() => {
      setPet(prev => {
        if (prev.isSleeping) {
          const newEnergy = Math.min(MAX_STAT, prev.energy + 8);
          return {
            ...prev,
            energy: newEnergy,
            hunger: Math.max(0, prev.hunger - 0.4),
            isSleeping: newEnergy >= MAX_STAT ? false : true
          };
        }
        return {
          ...prev,
          hunger: Math.max(0, prev.hunger - 0.25),
          happiness: Math.max(0, prev.happiness - 0.15),
          energy: Math.max(0, prev.energy - 0.2),
        };
      });
    }, 5000);

    return () => clearInterval(interval);
  }, [pet.isAdopted]);

  useEffect(() => {
    if (isARMode) {
      startCamera();
      visionInterval.current = window.setInterval(captureAndAnalyze, 4000);
    } else {
      stopCamera();
      if (visionInterval.current) clearInterval(visionInterval.current);
      setLastInteraction('none');
      setIsReacting(false);
    }
    return () => {
      stopCamera();
      if (visionInterval.current) clearInterval(visionInterval.current);
    };
  }, [isARMode]);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } });
      if (videoRef.current) videoRef.current.srcObject = stream;
    } catch (err) {
      setIsARMode(false);
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
      videoRef.current.srcObject = null;
    }
  };

  const spawnParticles = (count: number, char: string) => {
    const newParticles = Array.from({ length: count }).map(() => ({
      id: Math.random(),
      x: 30 + Math.random() * 40, // Center area of the image
      y: 40 + Math.random() * 20,
      char
    }));
    setParticles(prev => [...prev, ...newParticles]);
    setTimeout(() => {
      setParticles(prev => prev.filter(p => !newParticles.find(np => np.id === p.id)));
    }, 1500);
  };

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || isAnalyzing || !isARMode) return;

    setIsAnalyzing(true);
    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = 400; 
    canvas.height = (video.videoHeight / video.videoWidth) * 400;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    const base64 = canvas.toDataURL('image/jpeg', 0.6).split(',')[1];

    const result = await detectActivityFromImage(base64);
    setIsAnalyzing(false);

    if (result.confidence > 0.45) {
      if (result.interaction === lastInteraction && result.interaction !== 'belly_rub_active') return; 

      setLastInteraction(result.interaction);

      if (result.interaction === 'belly_rub_hand') {
        setVisionFeedback(`${pet.name} sees your hand and is curious!`);
        setIsReacting(false);
        triggerNewImage('curiously approaching a human hand, looking up with wagging tail', true);
      } else if (result.interaction === 'belly_rub_active') {
        setVisionFeedback(`Oh yes! ${pet.name} loves the belly rub! ✨`);
        setIsReacting(true);
        spawnParticles(5, '❤️');
        const activity = ACTIVITIES.find(a => a.id === 'belly-rub');
        if (activity) handleAction(activity, true, 'lying on its back being happily scratched on the belly by a human hand');
      } else if (result.interaction === 'feed_hand') {
        setVisionFeedback(`Nom nom! ${pet.name} is enjoying the treat! 🦴`);
        setIsReacting(true);
        spawnParticles(5, '✨');
        const activity = ACTIVITIES.find(a => a.id === 'feed');
        if (activity) handleAction(activity, true, 'happily eating a treat from a human hand');
      } else if (result.interaction === 'play_hand') {
        setVisionFeedback(`${pet.name} is eager to play fetch! 🎾`);
        setIsReacting(true);
        spawnParticles(5, '⭐');
        const activity = ACTIVITIES.find(a => a.id === 'play');
        if (activity) handleAction(activity, true, 'jumping excitedly towards a ball held by a human hand');
      } else {
        setIsReacting(false);
      }
    } else {
      setIsReacting(false);
      setVisionFeedback('');
    }
  };

  const handleAdopt = () => {
    if (!pet.name.trim()) return;
    setPet(prev => ({ ...prev, isAdopted: true, adoptedAt: Date.now() }));
  };

  const handleAction = async (activity: Activity, fromAR: boolean = false, arContext?: string) => {
    const updatedPet = {
      ...pet,
      hunger: Math.min(MAX_STAT, pet.hunger + activity.hungerEffect),
      happiness: Math.min(MAX_STAT, pet.happiness + activity.happinessEffect),
      energy: Math.max(0, pet.energy + activity.energyEffect),
      xp: pet.xp + activity.xpGain
    };

    if (updatedPet.xp >= XP_PER_LEVEL) {
      updatedPet.level += 1;
      updatedPet.ageMonths += 1;
      updatedPet.xp = updatedPet.xp - XP_PER_LEVEL;
      setShowLevelUp(true);
      setTimeout(() => setShowLevelUp(false), 4000);
      triggerNewImage('growing up and looking proud');
    }

    setPet(updatedPet);

    setIsTyping(true);
    const aiResp = await generateCorgiResponse(`I just ${activity.name.toLowerCase()} with you!`, updatedPet, []);
    setIsTyping(false);

    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);

    if (fromAR && arContext) {
      triggerNewImage(arContext, true);
    } else if (!fromAR && Math.random() > 0.6) {
      triggerNewImage(activity.name.toLowerCase());
    }
  };

  const triggerNewImage = async (context: string, isAR: boolean = false) => {
    setIsGeneratingImage(true);
    const newImg = await generateCorgiImage(pet, context, isAR);
    if (newImg) setPetImage(newImg);
    setIsGeneratingImage(false);
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim()) return;
    const userMsg = inputValue;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInputValue('');
    setIsTyping(true);
    const aiResp = await generateCorgiResponse(userMsg, pet, []);
    setIsTyping(false);
    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);
    setPet(prev => ({ ...prev, happiness: Math.min(MAX_STAT, prev.happiness + 2) }));
  };

  const toggleSleep = () => {
    setPet(prev => ({ ...prev, isSleeping: !prev.isSleeping }));
    if (!pet.isSleeping) {
      triggerNewImage('sleeping peacefully in a cozy bed');
    } else {
      triggerNewImage('waking up and stretching');
    }
  };

  const getBondedTime = () => {
    const diff = Date.now() - pet.adoptedAt;
    const minutes = Math.floor(diff / (1000 * 60));
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
    if (days > 0) return `${days} Day${days > 1 ? 's' : ''}`;
    if (hours > 0) return `${hours} Hour${hours > 1 ? 's' : ''}`;
    if (minutes > 0) return `${minutes} Min${minutes > 1 ? 's' : ''}`;
    return "Just Now";
  };

  if (!pet.isAdopted) {
    return (
      <div className="min-h-screen bg-[#fdf6e3] flex flex-col items-center justify-center p-6 bg-[url('https://www.transparenttextures.com/patterns/paws.png')]">
        <div className="max-w-2xl w-full bg-white rounded-[3.5rem] shadow-2xl p-10 md:p-14 border-[12px] border-orange-100 animate-in fade-in slide-in-from-top-4 duration-700 relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-2 bg-orange-400"></div>
          <div className="text-center mb-10">
            <span className="text-7xl block mb-6 animate-bounce">🦴</span>
            <h1 className="text-5xl font-brand text-orange-600 mb-3 tracking-tight">Electronic Breeder</h1>
            <p className="text-stone-500 font-semibold text-lg italic">Adopt and raise your unique companion</p>
          </div>
          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-2">
                <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">1. Select Breed</label>
                <select value={pet.breed} onChange={(e) => setPet(prev => ({ ...prev, breed: e.target.value }))} className="w-full p-5 rounded-2xl bg-orange-50/50 border-2 border-orange-100 focus:border-orange-400 focus:outline-none transition-all font-bold text-stone-700 appearance-none shadow-sm cursor-pointer">
                  {BREEDS.map(b => <option key={b} value={b}>{b}</option>)}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">2. Starting Month</label>
                <input type="number" min="2" max="36" value={pet.ageMonths} onChange={(e) => setPet(prev => ({ ...prev, ageMonths: parseInt(e.target.value) || 2 }))} className="w-full p-5 rounded-2xl bg-orange-50/50 border-2 border-orange-100 focus:border-orange-400 focus:outline-none transition-all font-bold text-stone-700 shadow-sm" />
              </div>
            </div>
            <div className="space-y-3">
              <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">3. Coat Appearance</label>
              <div className="grid grid-cols-3 gap-3">
                {COLORS.map(c => (
                  <button key={c} onClick={() => setPet(prev => ({ ...prev, color: c }))} className={`p-4 text-[10px] font-black rounded-2xl border-2 transition-all shadow-sm ${pet.color === c ? 'border-orange-400 bg-orange-500 text-white scale-105' : 'border-orange-100 bg-white text-stone-500 hover:border-orange-300'}`}>
                    {c}
                  </button>
                ))}
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">4. Name Your Corgi</label>
              <input type="text" placeholder="Give your friend a name..." value={pet.name} onChange={(e) => setPet(prev => ({ ...prev, name: e.target.value }))} className="w-full p-6 rounded-3xl bg-stone-50 border-2 border-stone-200 focus:border-orange-400 focus:outline-none transition-all font-brand text-2xl text-stone-800 placeholder:text-stone-300 text-center" />
            </div>
            <button onClick={handleAdopt} disabled={!pet.name.trim()} className="w-full py-6 bg-orange-500 hover:bg-orange-600 text-white rounded-[2rem] font-brand text-2xl shadow-2xl hover:shadow-orange-300/60 transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed transform hover:-translate-y-1">
              Start Raising {pet.name || 'Your Dog'} ✨
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col items-center bg-[#fdf6e3] p-4 md:p-10 relative overflow-x-hidden">
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/paws.png')]"></div>

      <header className="w-full max-w-6xl flex flex-col md:flex-row justify-between items-center gap-6 mb-12 relative z-10">
        <div className="text-center md:text-left">
          <h1 className="text-5xl font-brand text-orange-600 drop-shadow-sm flex items-center gap-3 justify-center md:justify-start">
            <span className="animate-pulse">🐾</span> {pet.name}'s World
          </h1>
          <p className="text-lg text-stone-500 font-bold mt-1">
            {pet.ageMonths} Month Old {pet.breed} • <span className="text-orange-400">{pet.color}</span>
          </p>
        </div>

        <div className="flex items-center gap-5">
          <button 
            onClick={() => setIsARMode(!isARMode)}
            className={`p-4 rounded-[2rem] font-black text-sm uppercase tracking-widest transition-all shadow-xl border-4 flex items-center gap-3 ${
              isARMode 
              ? 'bg-red-500 text-white border-red-200' 
              : 'bg-white text-orange-600 border-orange-100 hover:scale-105'
            }`}
          >
            <span className="text-2xl">{isARMode ? '⏹️' : '📷'}</span>
            {isARMode ? 'Stop AR' : 'Start AR'}
          </button>

          <div className="bg-white px-6 py-4 rounded-[2rem] shadow-xl border-4 border-orange-100 flex items-center gap-5 transform hover:scale-105 transition-transform">
            <div className="text-4xl">🏅</div>
            <div>
              <div className="text-xs uppercase font-black text-stone-400 tracking-tighter">Level</div>
              <div className="text-3xl font-brand text-orange-500 leading-none">{pet.level}</div>
            </div>
            <div className="h-12 w-1 bg-stone-100 rounded-full mx-1"></div>
            <div className="flex-1 min-w-[120px]">
              <div className="flex justify-between items-end mb-2 text-xs font-black text-stone-400">XP {pet.xp}/{XP_PER_LEVEL}</div>
              <div className="w-full h-3 bg-gray-100 rounded-full overflow-hidden shadow-inner">
                <div className="h-full bg-orange-400 transition-all duration-1000 ease-out rounded-full" style={{ width: `${(pet.xp / XP_PER_LEVEL) * 100}%` }}></div>
              </div>
            </div>
          </div>
        </div>
      </header>

      <main className="w-full max-w-7xl grid grid-cols-1 lg:grid-cols-2 gap-12 items-start relative z-10">
        <div className="space-y-10">
          <div className="relative group overflow-hidden rounded-[4rem] bg-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] border-[16px] border-white aspect-square flex items-center justify-center">
             {isARMode ? (
               <div className="absolute inset-0 z-0">
                 <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover grayscale opacity-20 transition-opacity" />
                 <canvas ref={canvasRef} className="hidden" />

                 {/* AR Focus Pulse */}
                 {isAnalyzing && (
                   <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-32 h-32 border-8 border-orange-400/30 rounded-full animate-ping pointer-events-none"></div>
                 )}

                 {/* Particle Effects */}
                 {particles.map(p => (
                   <span key={p.id} className="particle text-4xl" style={{ left: `${p.x}%`, top: `${p.y}%` }}>
                     {p.char}
                   </span>
                 ))}

                 <div className="absolute inset-x-10 bottom-10 flex items-center justify-center pointer-events-none z-50">
                    {visionFeedback && (
                      <div className="bg-white/95 text-orange-600 font-brand text-center text-2xl p-6 rounded-[2.5rem] animate-in slide-in-from-bottom-5 shadow-2xl border-4 border-orange-100 max-w-md relative">
                        <div className="absolute -top-3 left-1/2 -translate-x-1/2 w-6 h-6 bg-white border-t-4 border-l-4 border-orange-100 rotate-45"></div>
                        {visionFeedback}
                      </div>
                    )}
                 </div>
               </div>
             ) : (
               isGeneratingImage && (
                 <div className="absolute inset-0 z-20 bg-white/90 backdrop-blur-xl flex flex-col items-center justify-center">
                   <div className="animate-spin text-7xl mb-6">📷</div>
                   <div className="text-orange-600 font-brand text-2xl animate-pulse">Drawing {pet.name}...</div>
                 </div>
               )
             )}

             <img 
               src={petImage || `https://picsum.photos/seed/${pet.name}/800/800`} 
               alt={pet.name} 
               className={`w-full h-full object-cover transition-all duration-700 z-10 
                 ${pet.isSleeping ? 'brightness-50 grayscale' : ''} 
                 ${isARMode ? 'scale-90' : 'group-hover:scale-110'} 
                 ${isReacting ? 'pet-reacting' : ''}`}
             />

             {pet.isSleeping && <div className="absolute top-16 right-16 text-8xl animate-bounce z-20">💤</div>}
          </div>

          <div className="bg-white p-10 rounded-[3.5rem] shadow-2xl space-y-8 border-4 border-orange-50">
            <h3 className="font-brand text-3xl text-stone-700 flex items-center gap-4">🩺 Vital Signs</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
              <StatusBar label="Hunger" value={pet.hunger} color="bg-amber-400" icon="🥩" />
              <StatusBar label="Mood" value={pet.happiness} color="bg-pink-400" icon="💖" />
              <StatusBar label="Energy" value={pet.energy} color="bg-cyan-400" icon="⚡" />
            </div>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
            {ACTIVITIES.map(act => (
              <button key={act.id} onClick={() => handleAction(act)} disabled={pet.isSleeping} className={`flex flex-col items-center justify-center p-8 rounded-[2.5rem] bg-white shadow-xl border-b-[12px] border-stone-100 transition-all group ${pet.isSleeping ? 'opacity-30 grayscale cursor-not-allowed' : 'hover:-translate-y-2'}`}>
                <span className="text-5xl mb-3 group-hover:scale-125 transition-transform">{act.icon}</span>
                <span className="text-sm font-black text-stone-600 uppercase tracking-tighter text-center">{act.name}</span>
              </button>
            ))}
            <button onClick={toggleSleep} className={`col-span-2 md:col-span-4 flex items-center justify-center gap-5 p-8 rounded-[3rem] shadow-2xl border-b-[12px] transition-all ${pet.isSleeping ? 'bg-indigo-700 text-white border-indigo-900' : 'bg-white text-stone-700 border-stone-100 hover:bg-stone-50'}`}>
              <span className="text-4xl">{pet.isSleeping ? '☀️' : '🌙'}</span>
              <span className="font-brand text-2xl">{pet.isSleeping ? 'Good Morning!' : 'Time for Nap'}</span>
            </button>
          </div>
        </div>

        <div className="bg-white rounded-[4rem] shadow-2xl flex flex-col h-[700px] lg:h-[950px] border-8 border-orange-50 overflow-hidden relative">
          <div className="p-8 border-b-4 border-orange-50 bg-orange-50/20 flex items-center gap-6">
            <div className="w-20 h-20 rounded-3xl bg-orange-300 flex items-center justify-center text-5xl">🐕</div>
            <div>
              <h3 className="font-brand text-stone-700 text-3xl mb-2">{pet.name}'s Diary</h3>
              <p className="text-xs text-orange-600 font-black uppercase flex items-center gap-2">
                <span className="w-2 h-2 bg-green-500 rounded-full animate-ping"></span> Live Bark Translator
              </p>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-10 space-y-8 scroll-smooth scrollbar-hide">
            {isARMode && (
              <div className="p-6 bg-orange-100/50 rounded-3xl border-2 border-orange-200 mb-4 animate-in fade-in">
                <p className="text-orange-800 font-bold flex items-center gap-3">
                  <span className="text-2xl animate-spin">👀</span> Interaction Mode Active!
                </p>
                <p className="text-stone-500 text-sm mt-1">Try to reach out with your hand to scratch its belly or offer a treat.</p>
              </div>
            )}
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] rounded-[2.5rem] p-7 shadow-lg relative ${msg.role === 'user' ? 'bg-orange-500 text-white rounded-tr-none' : 'bg-stone-50 text-stone-800 rounded-tl-none border-2 border-stone-100'}`}>
                  <p className="font-bold text-xl">{msg.text}</p>
                  {msg.translation && <div className="mt-6 pt-6 border-t-2 border-black/5 text-base italic font-semibold opacity-80 text-stone-600"><span className="text-[11px] block font-black uppercase tracking-[0.2em] text-orange-400 mb-2">Thoughts</span>"{msg.translation}"</div>}
                </div>
              </div>
            ))}
            {isTyping && <div className="flex justify-start"><div className="bg-stone-50 border-2 border-stone-100 rounded-full px-10 py-5 flex gap-3 animate-pulse">...</div></div>}
            <div ref={chatEndRef} />
          </div>

          <form onSubmit={handleSendMessage} className="p-8 bg-white border-t-4 border-orange-50">
            <div className="flex gap-4 items-center bg-stone-50 p-3 rounded-[2.5rem] border-4 border-stone-100 focus-within:border-orange-400 shadow-inner">
              <input type="text" value={inputValue} onChange={(e) => setInputValue(e.target.value)} placeholder={`Talk to ${pet.name}...`} className="flex-1 p-4 bg-transparent border-none focus:outline-none font-bold text-xl text-stone-700" />
              <button type="submit" className="bg-orange-500 text-white w-16 h-16 rounded-[1.5rem] flex items-center justify-center font-bold shadow-2xl hover:scale-105 active:scale-90 transition-all">🐾</button>
            </div>
          </form>
        </div>
      </main>

      <footer className="mt-20 w-full max-w-6xl grid grid-cols-2 md:grid-cols-4 gap-6 pb-20 relative z-10">
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🎂</span><span className="text-xs font-black text-stone-400 uppercase">Growth</span><p className="font-brand text-2xl text-stone-700">{pet.ageMonths} Mos</p></div>
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🧬</span><span className="text-xs font-black text-stone-400 uppercase">Breed</span><p className="font-brand text-2xl text-stone-700">{pet.breed.split(' ')[0]}</p></div>
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🏡</span><span className="text-xs font-black text-stone-400 uppercase">Bonded</span><p className="font-brand text-2xl text-stone-700">{getBondedTime()}</p></div>
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">✨</span><span className="text-xs font-black text-stone-400 uppercase">Status</span><p className="font-brand text-2xl text-green-500">THRIVING</p></div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { PetState, CorgiMessage, Activity } from './types';
import { INITIAL_STATE, ACTIVITIES, MAX_STAT, XP_PER_LEVEL, BREEDS, COLORS } from './constants';
import StatusBar from './components/StatusBar';
import { generateCorgiResponse, generateCorgiImage, detectActivityFromImage } from './services/geminiService';

const App: React.FC = () => {
  const [pet, setPet] = useState<PetState>(() => {
    const saved = localStorage.getItem('corgi-breeder-final-v1');
    return saved ? JSON.parse(saved) : INITIAL_STATE;
  });

  const [messages, setMessages] = useState<CorgiMessage[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [petImage, setPetImage] = useState<string>('');
  const [showLevelUp, setShowLevelUp] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);

  // AR Mode States
  const [isARMode, setIsARMode] = useState(false);
  const [visionFeedback, setVisionFeedback] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [lastInteraction, setLastInteraction] = useState<string>('none');
  const [isReacting, setIsReacting] = useState(false);
  const [particles, setParticles] = useState<{ id: number, x: number, y: number, char: string }[]>([]);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const visionInterval = useRef<number | null>(null);

  // Determine current animation class based on pet state
  const petAnimationClass = useMemo(() => {
    if (isReacting) return 'pet-reacting';
    if (pet.isSleeping) return 'animate-breathe opacity-80';
    if (pet.happiness > 80) return 'animate-wag';
    if (pet.happiness < 30 || pet.hunger < 20) return 'opacity-90 grayscale-[20%]';
    return 'animate-bounce-subtle';
  }, [isReacting, pet.isSleeping, pet.happiness, pet.hunger]);

  useEffect(() => {
    if (pet.isAdopted && messages.length === 0) {
      setMessages([{ 
        role: 'corgi', 
        text: `Bork bork! (Hello! My name is ${pet.name}. Let's be friends!)`, 
        mood: 'happy' 
      }]);
      triggerNewImage('excitedly greeting its new owner');
    }
  }, [pet.isAdopted]);

  useEffect(() => {
    localStorage.setItem('corgi-breeder-final-v1', JSON.stringify(pet));
  }, [pet]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  useEffect(() => {
    if (!pet.isAdopted) return;
    const interval = setInterval(() => {
      setPet(prev => {
        if (prev.isSleeping) {
          const newEnergy = Math.min(MAX_STAT, prev.energy + 8);
          return {
            ...prev,
            energy: newEnergy,
            hunger: Math.max(0, prev.hunger - 0.4),
            isSleeping: newEnergy >= MAX_STAT ? false : true
          };
        }
        return {
          ...prev,
          hunger: Math.max(0, prev.hunger - 0.25),
          happiness: Math.max(0, prev.happiness - 0.15),
          energy: Math.max(0, prev.energy - 0.2),
        };
      });
    }, 5000);

    return () => clearInterval(interval);
  }, [pet.isAdopted]);

  useEffect(() => {
    if (isARMode) {
      startCamera();
      visionInterval.current = window.setInterval(captureAndAnalyze, 4000);
    } else {
      stopCamera();
      if (visionInterval.current) clearInterval(visionInterval.current);
      setLastInteraction('none');
      setIsReacting(false);
    }
    return () => {
      stopCamera();
      if (visionInterval.current) clearInterval(visionInterval.current);
    };
  }, [isARMode]);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } });
      if (videoRef.current) videoRef.current.srcObject = stream;
    } catch (err) {
      setIsARMode(false);
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
      videoRef.current.srcObject = null;
    }
  };

  const spawnParticles = (count: number, char: string) => {
    const newParticles = Array.from({ length: count }).map(() => ({
      id: Math.random(),
      x: 30 + Math.random() * 40, 
      y: 40 + Math.random() * 20,
      char
    }));
    setParticles(prev => [...prev, ...newParticles]);
    setTimeout(() => {
      setParticles(prev => prev.filter(p => !newParticles.find(np => np.id === p.id)));
    }, 1500);
  };

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || isAnalyzing || !isARMode) return;

    setIsAnalyzing(true);
    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = 400; 
    canvas.height = (video.videoHeight / video.videoWidth) * 400;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    const base64 = canvas.toDataURL('image/jpeg', 0.6).split(',')[1];

    const result = await detectActivityFromImage(base64);
    setIsAnalyzing(false);

    if (result.confidence > 0.45) {
      if (result.interaction === lastInteraction && result.interaction !== 'belly_rub_active') return; 

      setLastInteraction(result.interaction);

      if (result.interaction === 'belly_rub_hand') {
        setVisionFeedback(`${pet.name} sees your hand and is curious!`);
        setIsReacting(false);
        triggerNewImage('curiously approaching a human hand, looking up with wagging tail', true);
      } else if (result.interaction === 'belly_rub_active') {
        setVisionFeedback(`Oh yes! ${pet.name} loves the belly rub! ✨`);
        setIsReacting(true);
        spawnParticles(5, '❤️');
        const activity = ACTIVITIES.find(a => a.id === 'belly-rub');
        if (activity) handleAction(activity, true, 'lying on its back being happily scratched on the belly by a human hand');
      } else if (result.interaction === 'feed_hand') {
        setVisionFeedback(`Nom nom! ${pet.name} is enjoying the treat! 🦴`);
        setIsReacting(true);
        spawnParticles(5, '✨');
        const activity = ACTIVITIES.find(a => a.id === 'feed');
        if (activity) handleAction(activity, true, 'happily eating a treat from a human hand');
      } else if (result.interaction === 'play_hand') {
        setVisionFeedback(`${pet.name} is eager to play fetch! 🎾`);
        setIsReacting(true);
        spawnParticles(5, '⭐');
        const activity = ACTIVITIES.find(a => a.id === 'play');
        if (activity) handleAction(activity, true, 'jumping excitedly towards a ball held by a human hand');
      } else {
        setIsReacting(false);
      }
    } else {
      setIsReacting(false);
      setVisionFeedback('');
    }
  };

  const handleAdopt = () => {
    if (!pet.name.trim()) return;
    setPet(prev => ({ ...prev, isAdopted: true, adoptedAt: Date.now() }));
  };

  const handleAction = async (activity: Activity, fromAR: boolean = false, arContext?: string) => {
    const updatedPet = {
      ...pet,
      hunger: Math.min(MAX_STAT, pet.hunger + activity.hungerEffect),
      happiness: Math.min(MAX_STAT, pet.happiness + activity.happinessEffect),
      energy: Math.max(0, pet.energy + activity.energyEffect),
      xp: pet.xp + activity.xpGain
    };

    if (updatedPet.xp >= XP_PER_LEVEL) {
      updatedPet.level += 1;
      updatedPet.ageMonths += 1;
      updatedPet.xp = updatedPet.xp - XP_PER_LEVEL;
      setShowLevelUp(true);
      setTimeout(() => setShowLevelUp(false), 4000);
      triggerNewImage('growing up and looking proud');
    }

    setPet(updatedPet);

    setIsTyping(true);
    const aiResp = await generateCorgiResponse(`I just ${activity.name.toLowerCase()} with you!`, updatedPet, []);
    setIsTyping(false);

    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);

    if (fromAR && arContext) {
      triggerNewImage(arContext, true);
    } else if (!fromAR && Math.random() > 0.6) {
      triggerNewImage(activity.name.toLowerCase());
    }
  };

  const triggerNewImage = async (context: string, isAR: boolean = false) => {
    setIsGeneratingImage(true);
    const newImg = await generateCorgiImage(pet, context, isAR);
    if (newImg) setPetImage(newImg);
    setIsGeneratingImage(false);
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim()) return;
    const userMsg = inputValue;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInputValue('');
    setIsTyping(true);
    const aiResp = await generateCorgiResponse(userMsg, pet, []);
    setIsTyping(false);
    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);
    setPet(prev => ({ ...prev, happiness: Math.min(MAX_STAT, prev.happiness + 2) }));
  };

  const toggleSleep = () => {
    setPet(prev => ({ ...prev, isSleeping: !prev.isSleeping }));
    if (!pet.isSleeping) {
      triggerNewImage('sleeping peacefully in a cozy bed');
    } else {
      triggerNewImage('waking up and stretching');
    }
  };

  const getBondedTime = () => {
    const diff = Date.now() - pet.adoptedAt;
    const minutes = Math.floor(diff / (1000 * 60));
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
    if (days > 0) return `${days} Day${days > 1 ? 's' : ''}`;
    if (hours > 0) return `${hours} Hour${hours > 1 ? 's' : ''}`;
    if (minutes > 0) return `${minutes} Min${minutes > 1 ? 's' : ''}`;
    return "Just Now";
  };

  if (!pet.isAdopted) {
    return (
      <div className="min-h-screen bg-[#fdf6e3] flex flex-col items-center justify-center p-6 bg-[url('https://www.transparenttextures.com/patterns/paws.png')]">
        <div className="max-w-2xl w-full bg-white rounded-[3.5rem] shadow-2xl p-10 md:p-14 border-[12px] border-orange-100 animate-in fade-in slide-in-from-top-4 duration-700 relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-2 bg-orange-400"></div>
          <div className="text-center mb-10">
            <span className="text-7xl block mb-6 animate-bounce">🦴</span>
            <h1 className="text-5xl font-brand text-orange-600 mb-3 tracking-tight">Electronic Breeder</h1>
            <p className="text-stone-500 font-semibold text-lg italic">Adopt and raise your unique companion</p>
          </div>
          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-2">
                <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">1. Select Breed</label>
                <select value={pet.breed} onChange={(e) => setPet(prev => ({ ...prev, breed: e.target.value }))} className="w-full p-5 rounded-2xl bg-orange-50/50 border-2 border-orange-100 focus:border-orange-400 focus:outline-none transition-all font-bold text-stone-700 appearance-none shadow-sm cursor-pointer">
                  {BREEDS.map(b => <option key={b} value={b}>{b}</option>)}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">2. Starting Month</label>
                <input type="number" min="2" max="36" value={pet.ageMonths} onChange={(e) => setPet(prev => ({ ...prev, ageMonths: parseInt(e.target.value) || 2 }))} className="w-full p-5 rounded-2xl bg-orange-50/50 border-2 border-orange-100 focus:border-orange-400 focus:outline-none transition-all font-bold text-stone-700 shadow-sm" />
              </div>
            </div>
            <div className="space-y-3">
              <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">3. Coat Appearance</label>
              <div className="grid grid-cols-3 gap-3">
                {COLORS.map(c => (
                  <button key={c} onClick={() => setPet(prev => ({ ...prev, color: c }))} className={`p-4 text-[10px] font-black rounded-2xl border-2 transition-all shadow-sm ${pet.color === c ? 'border-orange-400 bg-orange-500 text-white scale-105' : 'border-orange-100 bg-white text-stone-500 hover:border-orange-300'}`}>
                    {c}
                  </button>
                ))}
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">4. Name Your Corgi</label>
              <input type="text" placeholder="Give your friend a name..." value={pet.name} onChange={(e) => setPet(prev => ({ ...prev, name: e.target.value }))} className="w-full p-6 rounded-3xl bg-stone-50 border-2 border-stone-200 focus:border-orange-400 focus:outline-none transition-all font-brand text-2xl text-stone-800 placeholder:text-stone-300 text-center" />
            </div>
            <button onClick={handleAdopt} disabled={!pet.name.trim()} className="w-full py-6 bg-orange-500 hover:bg-orange-600 text-white rounded-[2rem] font-brand text-2xl shadow-2xl hover:shadow-orange-300/60 transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed transform hover:-translate-y-1">
              Start Raising {pet.name || 'Your Dog'} ✨
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col items-center bg-[#fdf6e3] p-4 md:p-10 relative overflow-x-hidden">
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/paws.png')]"></div>

      <header className="w-full max-w-6xl flex flex-col md:flex-row justify-between items-center gap-6 mb-12 relative z-10">
        <div className="text-center md:text-left">
          <h1 className="text-5xl font-brand text-orange-600 drop-shadow-sm flex items-center gap-3 justify-center md:justify-start">
            <span className="animate-pulse">🐾</span> {pet.name}'s World
          </h1>
          <p className="text-lg text-stone-500 font-bold mt-1">
            {pet.ageMonths} Month Old {pet.breed} • <span className="text-orange-400">{pet.color}</span>
          </p>
        </div>

        <div className="flex items-center gap-5">
          <button 
            onClick={() => setIsARMode(!isARMode)}
            className={`p-4 rounded-[2rem] font-black text-sm uppercase tracking-widest transition-all shadow-xl border-4 flex items-center gap-3 ${
              isARMode 
              ? 'bg-red-500 text-white border-red-200' 
              : 'bg-white text-orange-600 border-orange-100 hover:scale-105'
            }`}
          >
            <span className="text-2xl">{isARMode ? '⏹️' : '📷'}</span>
            {isARMode ? 'Stop AR' : 'Start AR'}
          </button>

          <div className="bg-white px-6 py-4 rounded-[2rem] shadow-xl border-4 border-orange-100 flex items-center gap-5 transform hover:scale-105 transition-transform">
            <div className="text-4xl">🏅</div>
            <div>
              <div className="text-xs uppercase font-black text-stone-400 tracking-tighter">Level</div>
              <div className="text-3xl font-brand text-orange-500 leading-none">{pet.level}</div>
            </div>
            <div className="h-12 w-1 bg-stone-100 rounded-full mx-1"></div>
            <div className="flex-1 min-w-[120px]">
              <div className="flex justify-between items-end mb-2 text-xs font-black text-stone-400">XP {pet.xp}/{XP_PER_LEVEL}</div>
              <div className="w-full h-3 bg-gray-100 rounded-full overflow-hidden shadow-inner">
                <div className="h-full bg-orange-400 transition-all duration-1000 ease-out rounded-full" style={{ width: `${(pet.xp / XP_PER_LEVEL) * 100}%` }}></div>
              </div>
            </div>
          </div>
        </div>
      </header>

      <main className="w-full max-w-7xl grid grid-cols-1 lg:grid-cols-2 gap-12 items-start relative z-10">
        <div className="space-y-10">
          <div className="relative group overflow-hidden rounded-[4rem] bg-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] border-[16px] border-white aspect-square flex items-center justify-center">
             {isARMode ? (
               <div className="absolute inset-0 z-0">
                 <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover grayscale opacity-20 transition-opacity" />
                 <canvas ref={canvasRef} className="hidden" />

                 {/* AR Focus Pulse */}
                 {isAnalyzing && (
                   <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-32 h-32 border-8 border-orange-400/30 rounded-full animate-ping pointer-events-none"></div>
                 )}

                 {/* Particle Effects */}
                 {particles.map(p => (
                   <span key={p.id} className="particle text-4xl" style={{ left: `${p.x}%`, top: `${p.y}%` }}>
                     {p.char}
                   </span>
                 ))}

                 <div className="absolute inset-x-10 bottom-10 flex items-center justify-center pointer-events-none z-50">
                    {visionFeedback && (
                      <div className="bg-white/95 text-orange-600 font-brand text-center text-2xl p-6 rounded-[2.5rem] animate-in slide-in-from-bottom-5 shadow-2xl border-4 border-orange-100 max-w-md relative">
                        <div className="absolute -top-3 left-1/2 -translate-x-1/2 w-6 h-6 bg-white border-t-4 border-l-4 border-orange-100 rotate-45"></div>
                        {visionFeedback}
                      </div>
                    )}
                 </div>
               </div>
             ) : (
               isGeneratingImage && (
                 <div className="absolute inset-0 z-20 bg-white/90 backdrop-blur-xl flex flex-col items-center justify-center">
                   <div className="animate-spin text-7xl mb-6">📷</div>
                   <div className="text-orange-600 font-brand text-2xl animate-pulse">Drawing {pet.name}...</div>
                 </div>
               )
             )}

             <img 
               src={petImage || `https://picsum.photos/seed/${pet.name}/800/800`} 
               alt={pet.name} 
               className={`w-full h-full object-cover transition-all duration-700 z-10 
                 ${pet.isSleeping ? 'brightness-50 grayscale' : ''} 
                 ${isARMode ? 'scale-90' : 'group-hover:scale-110'} 
                 ${petAnimationClass}`}
             />

             {pet.isSleeping && <div className="absolute top-16 right-16 text-8xl animate-bounce z-20">💤</div>}
          </div>

          <div className="bg-white p-10 rounded-[3.5rem] shadow-2xl space-y-8 border-4 border-orange-50">
            <h3 className="font-brand text-3xl text-stone-700 flex items-center gap-4">🩺 Vital Signs</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
              <StatusBar label="Hunger" value={pet.hunger} color="bg-amber-400" icon="🥩" />
              <StatusBar label="Mood" value={pet.happiness} color="bg-pink-400" icon="💖" />
              <StatusBar label="Energy" value={pet.energy} color="bg-cyan-400" icon="⚡" />
            </div>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
            {ACTIVITIES.map(act => (
              <button key={act.id} onClick={() => handleAction(act)} disabled={pet.isSleeping} className={`flex flex-col items-center justify-center p-8 rounded-[2.5rem] bg-white shadow-xl border-b-[12px] border-stone-100 transition-all group ${pet.isSleeping ? 'opacity-30 grayscale cursor-not-allowed' : 'hover:-translate-y-2'}`}>
                <span className="text-5xl mb-3 group-hover:scale-125 transition-transform">{act.icon}</span>
                <span className="text-sm font-black text-stone-600 uppercase tracking-tighter text-center">{act.name}</span>
              </button>
            ))}
            <button onClick={toggleSleep} className={`col-span-2 md:col-span-4 flex items-center justify-center gap-5 p-8 rounded-[3rem] shadow-2xl border-b-[12px] transition-all ${pet.isSleeping ? 'bg-indigo-700 text-white border-indigo-900' : 'bg-white text-stone-700 border-stone-100 hover:bg-stone-50'}`}>
              <span className="text-4xl">{pet.isSleeping ? '☀️' : '🌙'}</span>
              <span className="font-brand text-2xl">{pet.isSleeping ? 'Good Morning!' : 'Time for Nap'}</span>
            </button>
          </div>
        </div>

        <div className="bg-white rounded-[4rem] shadow-2xl flex flex-col h-[700px] lg:h-[950px] border-8 border-orange-50 overflow-hidden relative">
          <div className="p-8 border-b-4 border-orange-50 bg-orange-50/20 flex items-center gap-6">
            <div className="w-20 h-20 rounded-3xl bg-orange-300 flex items-center justify-center text-5xl">🐕</div>
            <div>
              <h3 className="font-brand text-stone-700 text-3xl mb-2">{pet.name}'s Diary</h3>
              <p className="text-xs text-orange-600 font-black uppercase flex items-center gap-2">
                <span className="w-2 h-2 bg-green-500 rounded-full animate-ping"></span> Live Bark Translator
              </p>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-10 space-y-8 scroll-smooth scrollbar-hide">
            {isARMode && (
              <div className="p-6 bg-orange-100/50 rounded-3xl border-2 border-orange-200 mb-4 animate-in fade-in">
                <p className="text-orange-800 font-bold flex items-center gap-3">
                  <span className="text-2xl animate-spin">👀</span> Interaction Mode Active!
                </p>
                <p className="text-stone-500 text-sm mt-1">Try to reach out with your hand to scratch its belly or offer a treat.</p>
              </div>
            )}
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] rounded-[2.5rem] p-7 shadow-lg relative ${msg.role === 'user' ? 'bg-orange-500 text-white rounded-tr-none' : 'bg-stone-50 text-stone-800 rounded-tl-none border-2 border-stone-100'}`}>
                  <p className="font-bold text-xl">{msg.text}</p>
                  {msg.translation && <div className="mt-6 pt-6 border-t-2 border-black/5 text-base italic font-semibold opacity-80 text-stone-600"><span className="text-[11px] block font-black uppercase tracking-[0.2em] text-orange-400 mb-2">Thoughts</span>"{msg.translation}"</div>}
                </div>
              </div>
            ))}
            {isTyping && <div className="flex justify-start"><div className="bg-stone-50 border-2 border-stone-100 rounded-full px-10 py-5 flex gap-3 animate-pulse">...</div></div>}
            <div ref={chatEndRef} />
          </div>

          <form onSubmit={handleSendMessage} className="p-8 bg-white border-t-4 border-orange-50">
            <div className="flex gap-4 items-center bg-stone-50 p-3 rounded-[2.5rem] border-4 border-stone-100 focus-within:border-orange-400 shadow-inner">
              <input type="text" value={inputValue} onChange={(e) => setInputValue(e.target.value)} placeholder={`Talk to ${pet.name}...`} className="flex-1 p-4 bg-transparent border-none focus:outline-none font-bold text-xl text-stone-700" />
              <button type="submit" className="bg-orange-500 text-white w-16 h-16 rounded-[1.5rem] flex items-center justify-center font-bold shadow-2xl hover:scale-105 active:scale-90 transition-all">🐾</button>
            </div>
          </form>
        </div>
      </main>

      <footer className="mt-20 w-full max-w-6xl grid grid-cols-2 md:grid-cols-4 gap-6 pb-20 relative z-10">
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🎂</span><span className="text-xs font-black text-stone-400 uppercase">Growth</span><p className="font-brand text-2xl text-stone-700">{pet.ageMonths} Mos</p></div>
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🧬</span><span className="text-xs font-black text-stone-400 uppercase">Breed</span><p className="font-brand text-2xl text-stone-700">{pet.breed.split(' ')[0]}</p></div>
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🏡</span><span className="text-xs font-black text-stone-400 uppercase">Bonded</span><p className="font-brand text-2xl text-stone-700">{getBondedTime()}</p></div>
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">✨</span><span className="text-xs font-black text-stone-400 uppercase">Status</span><p className="font-brand text-2xl text-green-500">THRIVING</p></div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { PetState, CorgiMessage, Activity } from './types';
import { INITIAL_STATE, ACTIVITIES, MAX_STAT, XP_PER_LEVEL, BREEDS, COLORS } from './constants';
import StatusBar from './components/StatusBar';
import { generateCorgiResponse, generateCorgiImage, detectActivityFromImage } from './services/geminiService';

const App: React.FC = () => {
  const [pet, setPet] = useState<PetState>(() => {
    const saved = localStorage.getItem('corgi-breeder-final-v1');
    return saved ? JSON.parse(saved) : INITIAL_STATE;
  });

  const [messages, setMessages] = useState<CorgiMessage[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [petImage, setPetImage] = useState<string>('');
  const [showLevelUp, setShowLevelUp] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);

  // AR Mode States
  const [isARMode, setIsARMode] = useState(false);
  const [visionFeedback, setVisionFeedback] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [lastInteraction, setLastInteraction] = useState<string>('none');
  const [isReacting, setIsReacting] = useState(false);
  const [particles, setParticles] = useState<{ id: number, x: number, y: number, char: string }[]>([]);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const visionInterval = useRef<number | null>(null);

  // Determine current animation class based on pet state
  const petAnimationClass = useMemo(() => {
    if (isReacting) return 'pet-reacting';
    if (pet.isSleeping) return 'animate-breathe opacity-80';
    if (pet.happiness > 80) return 'animate-wag';
    if (pet.happiness < 30 || pet.hunger < 20) return 'opacity-90 grayscale-[20%]';
    return 'animate-bounce-subtle';
  }, [isReacting, pet.isSleeping, pet.happiness, pet.hunger]);

  useEffect(() => {
    if (pet.isAdopted && messages.length === 0) {
      setMessages([{ 
        role: 'corgi', 
        text: `Bork bork! (Hello! My name is ${pet.name}. Let's be friends!)`, 
        mood: 'happy' 
      }]);
      triggerNewImage('excitedly greeting its new owner');
    }
  }, [pet.isAdopted]);

  useEffect(() => {
    localStorage.setItem('corgi-breeder-final-v1', JSON.stringify(pet));
  }, [pet]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  useEffect(() => {
    if (!pet.isAdopted) return;
    const interval = setInterval(() => {
      setPet(prev => {
        if (prev.isSleeping) {
          const newEnergy = Math.min(MAX_STAT, prev.energy + 8);
          return {
            ...prev,
            energy: newEnergy,
            hunger: Math.max(0, prev.hunger - 0.4),
            isSleeping: newEnergy >= MAX_STAT ? false : true
          };
        }
        return {
          ...prev,
          hunger: Math.max(0, prev.hunger - 0.25),
          happiness: Math.max(0, prev.happiness - 0.15),
          energy: Math.max(0, prev.energy - 0.2),
        };
      });
    }, 5000);

    return () => clearInterval(interval);
  }, [pet.isAdopted]);

  useEffect(() => {
    if (isARMode) {
      startCamera();
      // Set initial state
      setVisionFeedback('Looking for interaction...');
      visionInterval.current = window.setInterval(captureAndAnalyze, 4000);
    } else {
      stopCamera();
      if (visionInterval.current) clearInterval(visionInterval.current);
      setLastInteraction('none');
      setIsReacting(false);
      setVisionFeedback('');
    }
    return () => {
      stopCamera();
      if (visionInterval.current) clearInterval(visionInterval.current);
    };
  }, [isARMode]);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } });
      if (videoRef.current) videoRef.current.srcObject = stream;
    } catch (err) {
      setIsARMode(false);
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
      videoRef.current.srcObject = null;
    }
  };

  const spawnParticles = (count: number, char: string) => {
    const newParticles = Array.from({ length: count }).map(() => ({
      id: Math.random(),
      x: 30 + Math.random() * 40, 
      y: 40 + Math.random() * 20,
      char
    }));
    setParticles(prev => [...prev, ...newParticles]);
    setTimeout(() => {
      setParticles(prev => prev.filter(p => !newParticles.find(np => np.id === p.id)));
    }, 1500);
  };

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || isAnalyzing || !isARMode) return;

    setIsAnalyzing(true);
    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = 400; 
    canvas.height = (video.videoHeight / video.videoWidth) * 400;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    const base64 = canvas.toDataURL('image/jpeg', 0.6).split(',')[1];

    const result = await detectActivityFromImage(base64);
    setIsAnalyzing(false);

    if (result.confidence > 0.45 && result.interaction !== 'none') {
      if (result.interaction === lastInteraction && result.interaction !== 'belly_rub_active') return; 

      setLastInteraction(result.interaction);

      if (result.interaction === 'belly_rub_hand') {
        setVisionFeedback(`${pet.name} sees your hand and is curious!`);
        setIsReacting(false);
        triggerNewImage('curiously approaching a human hand, looking up with wagging tail', true);
      } else if (result.interaction === 'belly_rub_active') {
        setVisionFeedback(`Oh yes! ${pet.name} loves the belly rub! ✨`);
        setIsReacting(true);
        spawnParticles(5, '❤️');
        const activity = ACTIVITIES.find(a => a.id === 'belly-rub');
        if (activity) handleAction(activity, true, 'lying on its back being happily scratched on the belly by a human hand');
      } else if (result.interaction === 'feed_hand') {
        setVisionFeedback(`Nom nom! ${pet.name} is enjoying the treat! 🦴`);
        setIsReacting(true);
        spawnParticles(5, '✨');
        const activity = ACTIVITIES.find(a => a.id === 'feed');
        if (activity) handleAction(activity, true, 'happily eating a treat from a human hand');
      } else if (result.interaction === 'play_hand') {
        setVisionFeedback(`${pet.name} is eager to play fetch! 🎾`);
        setIsReacting(true);
        spawnParticles(5, '⭐');
        const activity = ACTIVITIES.find(a => a.id === 'play');
        if (activity) handleAction(activity, true, 'jumping excitedly towards a ball held by a human hand');
      } else {
        setIsReacting(false);
        setVisionFeedback('Looking for interaction...');
      }
    } else {
      setIsReacting(false);
      setLastInteraction('none');
      setVisionFeedback('Looking for interaction...');
    }
  };

  const handleAdopt = () => {
    if (!pet.name.trim()) return;
    setPet(prev => ({ ...prev, isAdopted: true, adoptedAt: Date.now() }));
  };

  const handleAction = async (activity: Activity, fromAR: boolean = false, arContext?: string) => {
    const updatedPet = {
      ...pet,
      hunger: Math.min(MAX_STAT, pet.hunger + activity.hungerEffect),
      happiness: Math.min(MAX_STAT, pet.happiness + activity.happinessEffect),
      energy: Math.max(0, pet.energy + activity.energyEffect),
      xp: pet.xp + activity.xpGain
    };

    if (updatedPet.xp >= XP_PER_LEVEL) {
      updatedPet.level += 1;
      updatedPet.ageMonths += 1;
      updatedPet.xp = updatedPet.xp - XP_PER_LEVEL;
      setShowLevelUp(true);
      setTimeout(() => setShowLevelUp(false), 4000);
      triggerNewImage('growing up and looking proud');
    }

    setPet(updatedPet);

    setIsTyping(true);
    const aiResp = await generateCorgiResponse(`I just ${activity.name.toLowerCase()} with you!`, updatedPet, []);
    setIsTyping(false);

    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);

    if (fromAR && arContext) {
      triggerNewImage(arContext, true);
    } else if (!fromAR && Math.random() > 0.6) {
      triggerNewImage(activity.name.toLowerCase());
    }
  };

  const triggerNewImage = async (context: string, isAR: boolean = false) => {
    setIsGeneratingImage(true);
    const newImg = await generateCorgiImage(pet, context, isAR);
    if (newImg) setPetImage(newImg);
    setIsGeneratingImage(false);
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim()) return;
    const userMsg = inputValue;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInputValue('');
    setIsTyping(true);
    const aiResp = await generateCorgiResponse(userMsg, pet, []);
    setIsTyping(false);
    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);
    setPet(prev => ({ ...prev, happiness: Math.min(MAX_STAT, prev.happiness + 2) }));
  };

  const toggleSleep = () => {
    setPet(prev => ({ ...prev, isSleeping: !prev.isSleeping }));
    if (!pet.isSleeping) {
      triggerNewImage('sleeping peacefully in a cozy bed');
    } else {
      triggerNewImage('waking up and stretching');
    }
  };

  const getBondedTime = () => {
    const diff = Date.now() - pet.adoptedAt;
    const minutes = Math.floor(diff / (1000 * 60));
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
    if (days > 0) return `${days} Day${days > 1 ? 's' : ''}`;
    if (hours > 0) return `${hours} Hour${hours > 1 ? 's' : ''}`;
    if (minutes > 0) return `${minutes} Min${minutes > 1 ? 's' : ''}`;
    return "Just Now";
  };

  return (
    <div className="min-h-screen flex flex-col items-center bg-[#fdf6e3] p-4 md:p-10 relative overflow-x-hidden">
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/paws.png')]"></div>

      <header className="w-full max-w-6xl flex flex-col md:flex-row justify-between items-center gap-6 mb-12 relative z-10">
        <div className="text-center md:text-left">
          <h1 className="text-5xl font-brand text-orange-600 drop-shadow-sm flex items-center gap-3 justify-center md:justify-start">
            <span className="animate-pulse">🐾</span> {pet.name || 'Corgi'}'s World
          </h1>
          <p className="text-lg text-stone-500 font-bold mt-1">
            {pet.ageMonths} Month Old {pet.breed} • <span className="text-orange-400">{pet.color}</span>
          </p>
        </div>

        <div className="flex items-center gap-5">
          <button 
            onClick={() => setIsARMode(!isARMode)}
            className={`p-4 rounded-[2rem] font-black text-sm uppercase tracking-widest transition-all shadow-xl border-4 flex items-center gap-3 ${
              isARMode 
              ? 'bg-red-500 text-white border-red-200' 
              : 'bg-white text-orange-600 border-orange-100 hover:scale-105'
            }`}
          >
            <span className="text-2xl">{isARMode ? '⏹️' : '📷'}</span>
            {isARMode ? 'Stop AR' : 'Start AR'}
          </button>

          <div className="bg-white px-6 py-4 rounded-[2rem] shadow-xl border-4 border-orange-100 flex items-center gap-5 transform hover:scale-105 transition-transform">
            <div className="text-4xl">🏅</div>
            <div>
              <div className="text-xs uppercase font-black text-stone-400 tracking-tighter">Level</div>
              <div className="text-3xl font-brand text-orange-500 leading-none">{pet.level}</div>
            </div>
            <div className="h-12 w-1 bg-stone-100 rounded-full mx-1"></div>
            <div className="flex-1 min-w-[120px]">
              <div className="flex justify-between items-end mb-2 text-xs font-black text-stone-400">XP {pet.xp}/{XP_PER_LEVEL}</div>
              <div className="w-full h-3 bg-gray-100 rounded-full overflow-hidden shadow-inner">
                <div className="h-full bg-orange-400 transition-all duration-1000 ease-out rounded-full" style={{ width: `${(pet.xp / XP_PER_LEVEL) * 100}%` }}></div>
              </div>
            </div>
          </div>
        </div>
      </header>

      <main className="w-full max-w-7xl grid grid-cols-1 lg:grid-cols-2 gap-12 items-start relative z-10">
        {!pet.isAdopted ? (
          <div className="lg:col-span-2 w-full bg-white rounded-[3.5rem] shadow-2xl p-10 md:p-14 border-[12px] border-orange-100 animate-in fade-in slide-in-from-top-4 duration-700 relative overflow-hidden max-w-2xl mx-auto">
            <div className="absolute top-0 left-0 w-full h-2 bg-orange-400"></div>
            <div className="text-center mb-10">
              <span className="text-7xl block mb-6 animate-bounce">🦴</span>
              <h1 className="text-5xl font-brand text-orange-600 mb-3 tracking-tight">Electronic Breeder</h1>
              <p className="text-stone-500 font-semibold text-lg italic">Adopt and raise your unique companion</p>
            </div>
            <div className="space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">1. Select Breed</label>
                  <select value={pet.breed} onChange={(e) => setPet(prev => ({ ...prev, breed: e.target.value }))} className="w-full p-5 rounded-2xl bg-orange-50/50 border-2 border-orange-100 focus:border-orange-400 focus:outline-none transition-all font-bold text-stone-700 appearance-none shadow-sm cursor-pointer">
                    {BREEDS.map(b => <option key={b} value={b}>{b}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">2. Starting Month</label>
                  <input type="number" min="2" max="36" value={pet.ageMonths} onChange={(e) => setPet(prev => ({ ...prev, ageMonths: parseInt(e.target.value) || 2 }))} className="w-full p-5 rounded-2xl bg-orange-50/50 border-2 border-orange-100 focus:border-orange-400 focus:outline-none transition-all font-bold text-stone-700 shadow-sm" />
                </div>
              </div>
              <div className="space-y-3">
                <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">3. Coat Appearance</label>
                <div className="grid grid-cols-3 gap-3">
                  {COLORS.map(c => (
                    <button key={c} onClick={() => setPet(prev => ({ ...prev, color: c }))} className={`p-4 text-[10px] font-black rounded-2xl border-2 transition-all shadow-sm ${pet.color === c ? 'border-orange-400 bg-orange-500 text-white scale-105' : 'border-orange-100 bg-white text-stone-500 hover:border-orange-300'}`}>
                      {c}
                    </button>
                  ))}
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">4. Name Your Corgi</label>
                <input type="text" placeholder="Give your friend a name..." value={pet.name} onChange={(e) => setPet(prev => ({ ...prev, name: e.target.value }))} className="w-full p-6 rounded-3xl bg-stone-50 border-2 border-stone-200 focus:border-orange-400 focus:outline-none transition-all font-brand text-2xl text-stone-800 placeholder:text-stone-300 text-center" />
              </div>
              <button onClick={handleAdopt} disabled={!pet.name.trim()} className="w-full py-6 bg-orange-500 hover:bg-orange-600 text-white rounded-[2rem] font-brand text-2xl shadow-2xl hover:shadow-orange-300/60 transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed transform hover:-translate-y-1">
                Start Raising {pet.name || 'Your Dog'} ✨
              </button>
            </div>
          </div>
        ) : (
          <>
            <div className="space-y-10">
              <div className="relative group overflow-hidden rounded-[4rem] bg-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] border-[16px] border-white aspect-square flex items-center justify-center">
                 {isARMode ? (
                   <div className="absolute inset-0 z-0 overflow-hidden">
                     <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover grayscale opacity-20 transition-opacity" />
                     <canvas ref={canvasRef} className="hidden" />

                     {/* AR Focus Pulse */}
                     {isAnalyzing && (
                       <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-32 h-32 border-8 border-orange-400/30 rounded-full animate-ping pointer-events-none"></div>
                     )}

                     {/* Particle Effects */}
                     {particles.map(p => (
                       <span key={p.id} className="particle text-4xl" style={{ left: `${p.x}%`, top: `${p.y}%` }}>
                         {p.char}
                       </span>
                     ))}

                     <div className="absolute inset-x-10 bottom-10 flex items-center justify-center pointer-events-none z-50">
                        {visionFeedback && (
                          <div className={`bg-white/95 text-orange-600 font-brand text-center text-2xl p-6 rounded-[2.5rem] animate-in slide-in-from-bottom-5 shadow-2xl border-4 border-orange-100 max-w-md relative transition-all duration-500 ${visionFeedback === 'Looking for interaction...' ? 'opacity-70 scale-95 border-dashed' : 'opacity-100 scale-100 shadow-orange-200'}`}>
                            {visionFeedback !== 'Looking for interaction...' && <div className="absolute -top-3 left-1/2 -translate-x-1/2 w-6 h-6 bg-white border-t-4 border-l-4 border-orange-100 rotate-45"></div>}
                            {visionFeedback}
                          </div>
                        )}
                     </div>
                   </div>
                 ) : (
                   isGeneratingImage && (
                     <div className="absolute inset-0 z-20 bg-white/90 backdrop-blur-xl flex flex-col items-center justify-center">
                       <div className="animate-spin text-7xl mb-6">📷</div>
                       <div className="text-orange-600 font-brand text-2xl animate-pulse">Drawing {pet.name}...</div>
                     </div>
                   )
                 )}

                 <img 
                   src={petImage || `https://picsum.photos/seed/${pet.name}/800/800`} 
                   alt={pet.name} 
                   className={`w-full h-full object-cover transition-all duration-700 z-10 
                     ${pet.isSleeping ? 'brightness-50 grayscale' : ''} 
                     ${isARMode ? 'scale-90' : 'group-hover:scale-110'} 
                     ${petAnimationClass}`}
                 />

                 {pet.isSleeping && <div className="absolute top-16 right-16 text-8xl animate-bounce z-20">💤</div>}
              </div>

              <div className="bg-white p-10 rounded-[3.5rem] shadow-2xl space-y-8 border-4 border-orange-50">
                <h3 className="font-brand text-3xl text-stone-700 flex items-center gap-4">🩺 Vital Signs</h3>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
                  <StatusBar label="Hunger" value={pet.hunger} color="bg-amber-400" icon="🥩" />
                  <StatusBar label="Mood" value={pet.happiness} color="bg-pink-400" icon="💖" />
                  <StatusBar label="Energy" value={pet.energy} color="bg-cyan-400" icon="⚡" />
                </div>
              </div>

              <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                {ACTIVITIES.map(act => (
                  <button key={act.id} onClick={() => handleAction(act)} disabled={pet.isSleeping} className={`flex flex-col items-center justify-center p-8 rounded-[2.5rem] bg-white shadow-xl border-b-[12px] border-stone-100 transition-all group ${pet.isSleeping ? 'opacity-30 grayscale cursor-not-allowed' : 'hover:-translate-y-2'}`}>
                    <span className="text-5xl mb-3 group-hover:scale-125 transition-transform">{act.icon}</span>
                    <span className="text-sm font-black text-stone-600 uppercase tracking-tighter text-center">{act.name}</span>
                  </button>
                ))}
                <button onClick={toggleSleep} className={`col-span-2 md:col-span-4 flex items-center justify-center gap-5 p-8 rounded-[3rem] shadow-2xl border-b-[12px] transition-all ${pet.isSleeping ? 'bg-indigo-700 text-white border-indigo-900' : 'bg-white text-stone-700 border-stone-100 hover:bg-stone-50'}`}>
                  <span className="text-4xl">{pet.isSleeping ? '☀️' : '🌙'}</span>
                  <span className="font-brand text-2xl">{pet.isSleeping ? 'Good Morning!' : 'Time for Nap'}</span>
                </button>
              </div>
            </div>

            <div className="bg-white rounded-[4rem] shadow-2xl flex flex-col h-[700px] lg:h-[950px] border-8 border-orange-50 overflow-hidden relative">
              <div className="p-8 border-b-4 border-orange-50 bg-orange-50/20 flex items-center gap-6">
                <div className="w-20 h-20 rounded-3xl bg-orange-300 flex items-center justify-center text-5xl">🐕</div>
                <div>
                  <h3 className="font-brand text-stone-700 text-3xl mb-2">{pet.name}'s Diary</h3>
                  <p className="text-xs text-orange-600 font-black uppercase flex items-center gap-2">
                    <span className="w-2 h-2 bg-green-500 rounded-full animate-ping"></span> Live Bark Translator
                  </p>
                </div>
              </div>

              <div className="flex-1 overflow-y-auto p-10 space-y-8 scroll-smooth scrollbar-hide">
                {isARMode && (
                  <div className="p-6 bg-orange-100/50 rounded-3xl border-2 border-orange-200 mb-4 animate-in fade-in">
                    <p className="text-orange-800 font-bold flex items-center gap-3">
                      <span className="text-2xl animate-spin">👀</span> Interaction Mode Active!
                    </p>
                    <p className="text-stone-500 text-sm mt-1">Try to reach out with your hand to scratch its belly or offer a treat.</p>
                  </div>
                )}
                {messages.map((msg, idx) => (
                  <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[85%] rounded-[2.5rem] p-7 shadow-lg relative ${msg.role === 'user' ? 'bg-orange-500 text-white rounded-tr-none' : 'bg-stone-50 text-stone-800 rounded-tl-none border-2 border-stone-100'}`}>
                      <p className="font-bold text-xl">{msg.text}</p>
                      {msg.translation && <div className="mt-6 pt-6 border-t-2 border-black/5 text-base italic font-semibold opacity-80 text-stone-600"><span className="text-[11px] block font-black uppercase tracking-[0.2em] text-orange-400 mb-2">Thoughts</span>"{msg.translation}"</div>}
                    </div>
                  </div>
                ))}
                {isTyping && <div className="flex justify-start"><div className="bg-stone-50 border-2 border-stone-100 rounded-full px-10 py-5 flex gap-3 animate-pulse">...</div></div>}
                <div ref={chatEndRef} />
              </div>

              <form onSubmit={handleSendMessage} className="p-8 bg-white border-t-4 border-orange-50">
                <div className="flex gap-4 items-center bg-stone-50 p-3 rounded-[2.5rem] border-4 border-stone-100 focus-within:border-orange-400 shadow-inner">
                  <input type="text" value={inputValue} onChange={(e) => setInputValue(e.target.value)} placeholder={`Talk to ${pet.name}...`} className="flex-1 p-4 bg-transparent border-none focus:outline-none font-bold text-xl text-stone-700" />
                  <button type="submit" className="bg-orange-500 text-white w-16 h-16 rounded-[1.5rem] flex items-center justify-center font-bold shadow-2xl hover:scale-105 active:scale-90 transition-all">🐾</button>
                </div>
              </form>
            </div>
          </>
        )}
      </main>

      {pet.isAdopted && (
        <footer className="mt-20 w-full max-w-6xl grid grid-cols-2 md:grid-cols-4 gap-6 pb-20 relative z-10">
           <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🎂</span><span className="text-xs font-black text-stone-400 uppercase">Growth</span><p className="font-brand text-2xl text-stone-700">{pet.ageMonths} Mos</p></div>
           <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🧬</span><span className="text-xs font-black text-stone-400 uppercase">Breed</span><p className="font-brand text-2xl text-stone-700">{pet.breed.split(' ')[0]}</p></div>
           <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🏡</span><span className="text-xs font-black text-stone-400 uppercase">Bonded</span><p className="font-brand text-2xl text-stone-700">{getBondedTime()}</p></div>
           <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">✨</span><span className="text-xs font-black text-stone-400 uppercase">Status</span><p className="font-brand text-2xl text-green-500">THRIVING</p></div>
        </footer>
      )}
    </div>
  );
};

export default App;

{
  "name": "CorgiLife",
  "description": "Adopt and raise a virtual Corgi. Use the power of Gemini AI to translate barks, play together, and see your pet grow in this immersive virtual pet experience.",
  "requestFramePermissions": []
}

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { PetState, CorgiMessage, Activity } from './types';
import { INITIAL_STATE, ACTIVITIES, MAX_STAT, XP_PER_LEVEL, BREEDS, COLORS } from './constants';
import StatusBar from './components/StatusBar';
import { generateCorgiResponse, generateCorgiImage } from './services/geminiService';

const App: React.FC = () => {
  const [pet, setPet] = useState<PetState>(() => {
    const saved = localStorage.getItem('corgi-breeder-final-v1');
    return saved ? JSON.parse(saved) : INITIAL_STATE;
  });

  const [messages, setMessages] = useState<CorgiMessage[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [petImage, setPetImage] = useState<string>('');
  const [showLevelUp, setShowLevelUp] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);

  const chatEndRef = useRef<HTMLDivElement>(null);

  // Determine current animation class based on pet state
  const petAnimationClass = useMemo(() => {
    if (pet.isSleeping) return 'animate-breathe opacity-80';
    if (pet.happiness > 80) return 'animate-wag';
    if (pet.happiness < 30 || pet.hunger < 20) return 'opacity-90 grayscale-[20%]';
    return 'animate-bounce-subtle';
  }, [pet.isSleeping, pet.happiness, pet.hunger]);

  useEffect(() => {
    if (pet.isAdopted && messages.length === 0) {
      setMessages([{ 
        role: 'corgi', 
        text: `Bork bork! (Hello! My name is ${pet.name}. Let's be friends!)`, 
        mood: 'happy' 
      }]);
      triggerNewImage('excitedly greeting its new owner');
    }
  }, [pet.isAdopted]);

  useEffect(() => {
    localStorage.setItem('corgi-breeder-final-v1', JSON.stringify(pet));
  }, [pet]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  useEffect(() => {
    if (!pet.isAdopted) return;
    const interval = setInterval(() => {
      setPet(prev => {
        if (prev.isSleeping) {
          const newEnergy = Math.min(MAX_STAT, prev.energy + 8);
          return {
            ...prev,
            energy: newEnergy,
            hunger: Math.max(0, prev.hunger - 0.4),
            isSleeping: newEnergy >= MAX_STAT ? false : true
          };
        }
        return {
          ...prev,
          hunger: Math.max(0, prev.hunger - 0.25),
          happiness: Math.max(0, prev.happiness - 0.15),
          energy: Math.max(0, prev.energy - 0.2),
        };
      });
    }, 5000);

    return () => clearInterval(interval);
  }, [pet.isAdopted]);

  const handleAdopt = () => {
    if (!pet.name.trim()) return;
    setPet(prev => ({ ...prev, isAdopted: true, adoptedAt: Date.now() }));
  };

  const handleAction = async (activity: Activity) => {
    const updatedPet = {
      ...pet,
      hunger: Math.min(MAX_STAT, pet.hunger + activity.hungerEffect),
      happiness: Math.min(MAX_STAT, pet.happiness + activity.happinessEffect),
      energy: Math.max(0, pet.energy + activity.energyEffect),
      xp: pet.xp + activity.xpGain
    };

    if (updatedPet.xp >= XP_PER_LEVEL) {
      updatedPet.level += 1;
      updatedPet.ageMonths += 1;
      updatedPet.xp = updatedPet.xp - XP_PER_LEVEL;
      setShowLevelUp(true);
      setTimeout(() => setShowLevelUp(false), 4000);
      triggerNewImage('growing up and looking proud');
    }

    setPet(updatedPet);

    setIsTyping(true);
    const aiResp = await generateCorgiResponse(`I just ${activity.name.toLowerCase()} with you!`, updatedPet, []);
    setIsTyping(false);

    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);

    if (Math.random() > 0.6) {
      triggerNewImage(activity.name.toLowerCase());
    }
  };

  const triggerNewImage = async (context: string) => {
    setIsGeneratingImage(true);
    const newImg = await generateCorgiImage(pet, context);
    if (newImg) setPetImage(newImg);
    setIsGeneratingImage(false);
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim()) return;
    const userMsg = inputValue;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInputValue('');
    setIsTyping(true);
    const aiResp = await generateCorgiResponse(userMsg, pet, []);
    setIsTyping(false);
    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);
    setPet(prev => ({ ...prev, happiness: Math.min(MAX_STAT, prev.happiness + 2) }));
  };

  const toggleSleep = () => {
    setPet(prev => ({ ...prev, isSleeping: !prev.isSleeping }));
    if (!pet.isSleeping) {
      triggerNewImage('sleeping peacefully in a cozy bed');
    } else {
      triggerNewImage('waking up and stretching');
    }
  };

  const getBondedTime = () => {
    const diff = Date.now() - pet.adoptedAt;
    const minutes = Math.floor(diff / (1000 * 60));
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
    if (days > 0) return `${days} Day${days > 1 ? 's' : ''}`;
    if (hours > 0) return `${hours} Hour${hours > 1 ? 's' : ''}`;
    if (minutes > 0) return `${minutes} Min${minutes > 1 ? 's' : ''}`;
    return "Just Now";
  };

  return (
    <div className="min-h-screen flex flex-col items-center bg-[#fdf6e3] p-4 md:p-10 relative overflow-x-hidden">
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/paws.png')]"></div>

      <header className="w-full max-w-6xl flex flex-col md:flex-row justify-between items-center gap-6 mb-12 relative z-10">
        <div className="text-center md:text-left">
          <h1 className="text-5xl font-brand text-orange-600 drop-shadow-sm flex items-center gap-3 justify-center md:justify-start">
            <span className="animate-pulse">🐾</span> {pet.name || 'Corgi'}'s World
          </h1>
          <p className="text-lg text-stone-500 font-bold mt-1">
            {pet.ageMonths} Month Old {pet.breed} • <span className="text-orange-400">{pet.color}</span>
          </p>
        </div>

        <div className="flex items-center gap-5">
          <div className="bg-white px-6 py-4 rounded-[2rem] shadow-xl border-4 border-orange-100 flex items-center gap-5 transform hover:scale-105 transition-transform">
            <div className="text-4xl">🏅</div>
            <div>
              <div className="text-xs uppercase font-black text-stone-400 tracking-tighter">Level</div>
              <div className="text-3xl font-brand text-orange-500 leading-none">{pet.level}</div>
            </div>
            <div className="h-12 w-1 bg-stone-100 rounded-full mx-1"></div>
            <div className="flex-1 min-w-[120px]">
              <div className="flex justify-between items-end mb-2 text-xs font-black text-stone-400">XP {pet.xp}/{XP_PER_LEVEL}</div>
              <div className="w-full h-3 bg-gray-100 rounded-full overflow-hidden shadow-inner">
                <div className="h-full bg-orange-400 transition-all duration-1000 ease-out rounded-full" style={{ width: `${(pet.xp / XP_PER_LEVEL) * 100}%` }}></div>
              </div>
            </div>
          </div>
        </div>
      </header>

      <main className="w-full max-w-7xl grid grid-cols-1 lg:grid-cols-2 gap-12 items-start relative z-10">
        {!pet.isAdopted ? (
          <div className="lg:col-span-2 w-full bg-white rounded-[3.5rem] shadow-2xl p-10 md:p-14 border-[12px] border-orange-100 animate-in fade-in slide-in-from-top-4 duration-700 relative overflow-hidden max-w-2xl mx-auto">
            <div className="absolute top-0 left-0 w-full h-2 bg-orange-400"></div>
            <div className="text-center mb-10">
              <span className="text-7xl block mb-6 animate-bounce">🦴</span>
              <h1 className="text-5xl font-brand text-orange-600 mb-3 tracking-tight">Electronic Breeder</h1>
              <p className="text-stone-500 font-semibold text-lg italic">Adopt and raise your unique companion</p>
            </div>
            <div className="space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">1. Select Breed</label>
                  <select value={pet.breed} onChange={(e) => setPet(prev => ({ ...prev, breed: e.target.value }))} className="w-full p-5 rounded-2xl bg-orange-50/50 border-2 border-orange-100 focus:border-orange-400 focus:outline-none transition-all font-bold text-stone-700 appearance-none shadow-sm cursor-pointer">
                    {BREEDS.map(b => <option key={b} value={b}>{b}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">2. Starting Month</label>
                  <input type="number" min="2" max="36" value={pet.ageMonths} onChange={(e) => setPet(prev => ({ ...prev, ageMonths: parseInt(e.target.value) || 2 }))} className="w-full p-5 rounded-2xl bg-orange-50/50 border-2 border-orange-100 focus:border-orange-400 focus:outline-none transition-all font-bold text-stone-700 shadow-sm" />
                </div>
              </div>
              <div className="space-y-3">
                <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">3. Coat Appearance</label>
                <div className="grid grid-cols-3 gap-3">
                  {COLORS.map(c => (
                    <button key={c} onClick={() => setPet(prev => ({ ...prev, color: c }))} className={`p-4 text-[10px] font-black rounded-2xl border-2 transition-all shadow-sm ${pet.color === c ? 'border-orange-400 bg-orange-500 text-white scale-105' : 'border-orange-100 bg-white text-stone-500 hover:border-orange-300'}`}>
                      {c}
                    </button>
                  ))}
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">4. Name Your Corgi</label>
                <input type="text" placeholder="Give your friend a name..." value={pet.name} onChange={(e) => setPet(prev => ({ ...prev, name: e.target.value }))} className="w-full p-6 rounded-3xl bg-stone-50 border-2 border-stone-200 focus:border-orange-400 focus:outline-none transition-all font-brand text-2xl text-stone-800 placeholder:text-stone-300 text-center" />
              </div>
              <button onClick={handleAdopt} disabled={!pet.name.trim()} className="w-full py-6 bg-orange-500 hover:bg-orange-600 text-white rounded-[2rem] font-brand text-2xl shadow-2xl hover:shadow-orange-300/60 transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed transform hover:-translate-y-1">
                Start Raising {pet.name || 'Your Dog'} ✨
              </button>
            </div>
          </div>
        ) : (
          <>
            <div className="space-y-10">
              <div className="relative group overflow-hidden rounded-[4rem] bg-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] border-[16px] border-white aspect-square flex items-center justify-center">
                 {isGeneratingImage && (
                   <div className="absolute inset-0 z-20 bg-white/90 backdrop-blur-xl flex flex-col items-center justify-center">
                     <div className="animate-spin text-7xl mb-6">📷</div>
                     <div className="text-orange-600 font-brand text-2xl animate-pulse">Drawing {pet.name}...</div>
                   </div>
                 )}

                 <img 
                   src={petImage || `https://picsum.photos/seed/${pet.name}/800/800`} 
                   alt={pet.name} 
                   className={`w-full h-full object-cover transition-all duration-700 z-10 
                     ${pet.isSleeping ? 'brightness-50 grayscale' : ''} 
                     group-hover:scale-110 
                     ${petAnimationClass}`}
                 />

                 {pet.isSleeping && <div className="absolute top-16 right-16 text-8xl animate-bounce z-20">💤</div>}
              </div>

              <div className="bg-white p-10 rounded-[3.5rem] shadow-2xl space-y-8 border-4 border-orange-50">
                <h3 className="font-brand text-3xl text-stone-700 flex items-center gap-4">🩺 Vital Signs</h3>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
                  <StatusBar label="Hunger" value={pet.hunger} color="bg-amber-400" icon="🥩" />
                  <StatusBar label="Mood" value={pet.happiness} color="bg-pink-400" icon="💖" />
                  <StatusBar label="Energy" value={pet.energy} color="bg-cyan-400" icon="⚡" />
                </div>
              </div>

              <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                {ACTIVITIES.map(act => (
                  <button key={act.id} onClick={() => handleAction(act)} disabled={pet.isSleeping} className={`flex flex-col items-center justify-center p-8 rounded-[2.5rem] bg-white shadow-xl border-b-[12px] border-stone-100 transition-all group ${pet.isSleeping ? 'opacity-30 grayscale cursor-not-allowed' : 'hover:-translate-y-2'}`}>
                    <span className="text-5xl mb-3 group-hover:scale-125 transition-transform">{act.icon}</span>
                    <span className="text-sm font-black text-stone-600 uppercase tracking-tighter text-center">{act.name}</span>
                  </button>
                ))}
                <button onClick={toggleSleep} className={`col-span-2 md:col-span-4 flex items-center justify-center gap-5 p-8 rounded-[3rem] shadow-2xl border-b-[12px] transition-all ${pet.isSleeping ? 'bg-indigo-700 text-white border-indigo-900' : 'bg-white text-stone-700 border-stone-100 hover:bg-stone-50'}`}>
                  <span className="text-4xl">{pet.isSleeping ? '☀️' : '🌙'}</span>
                  <span className="font-brand text-2xl">{pet.isSleeping ? 'Good Morning!' : 'Time for Nap'}</span>
                </button>
              </div>
            </div>

            <div className="bg-white rounded-[4rem] shadow-2xl flex flex-col h-[700px] lg:h-[950px] border-8 border-orange-50 overflow-hidden relative">
              <div className="p-8 border-b-4 border-orange-50 bg-orange-50/20 flex items-center gap-6">
                <div className="w-20 h-20 rounded-3xl bg-orange-300 flex items-center justify-center text-5xl">🐕</div>
                <div>
                  <h3 className="font-brand text-stone-700 text-3xl mb-2">{pet.name}'s Diary</h3>
                  <p className="text-xs text-orange-600 font-black uppercase flex items-center gap-2">
                    <span className="w-2 h-2 bg-green-500 rounded-full animate-ping"></span> Live Bark Translator
                  </p>
                </div>
              </div>

              <div className="flex-1 overflow-y-auto p-10 space-y-8 scroll-smooth scrollbar-hide">
                {messages.map((msg, idx) => (
                  <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[85%] rounded-[2.5rem] p-7 shadow-lg relative ${msg.role === 'user' ? 'bg-orange-500 text-white rounded-tr-none' : 'bg-stone-50 text-stone-800 rounded-tl-none border-2 border-stone-100'}`}>
                      <p className="font-bold text-xl">{msg.text}</p>
                      {msg.translation && <div className="mt-6 pt-6 border-t-2 border-black/5 text-base italic font-semibold opacity-80 text-stone-600"><span className="text-[11px] block font-black uppercase tracking-[0.2em] text-orange-400 mb-2">Thoughts</span>"{msg.translation}"</div>}
                    </div>
                  </div>
                ))}
                {isTyping && <div className="flex justify-start"><div className="bg-stone-50 border-2 border-stone-100 rounded-full px-10 py-5 flex gap-3 animate-pulse">...</div></div>}
                <div ref={chatEndRef} />
              </div>

              <form onSubmit={handleSendMessage} className="p-8 bg-white border-t-4 border-orange-50">
                <div className="flex gap-4 items-center bg-stone-50 p-3 rounded-[2.5rem] border-4 border-stone-100 focus-within:border-orange-400 shadow-inner">
                  <input type="text" value={inputValue} onChange={(e) => setInputValue(e.target.value)} placeholder={`Talk to ${pet.name}...`} className="flex-1 p-4 bg-transparent border-none focus:outline-none font-bold text-xl text-stone-700" />
                  <button type="submit" className="bg-orange-500 text-white w-16 h-16 rounded-[1.5rem] flex items-center justify-center font-bold shadow-2xl hover:scale-105 active:scale-90 transition-all">🐾</button>
                </div>
              </form>
            </div>
          </>
        )}
      </main>

      {pet.isAdopted && (
        <footer className="mt-20 w-full max-w-6xl grid grid-cols-2 md:grid-cols-4 gap-6 pb-20 relative z-10">
           <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🎂</span><span className="text-xs font-black text-stone-400 uppercase">Growth</span><p className="font-brand text-2xl text-stone-700">{pet.ageMonths} Mos</p></div>
           <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🧬</span><span className="text-xs font-black text-stone-400 uppercase">Breed</span><p className="font-brand text-2xl text-stone-700">{pet.breed.split(' ')[0]}</p></div>
           <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">🏡</span><span className="text-xs font-black text-stone-400 uppercase">Bonded</span><p className="font-brand text-2xl text-stone-700">{getBondedTime()}</p></div>
           <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white"><span className="block text-4xl mb-2">✨</span><span className="text-xs font-black text-stone-400 uppercase">Status</span><p className="font-brand text-2xl text-green-500">THRIVING</p></div>
        </footer>
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { PetState } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });

export const generateCorgiResponse = async (
  userInput: string,
  petState: PetState,
  history: { role: 'user' | 'model', parts: { text: string }[] }[]
) => {
  const model = "gemini-3-flash-preview";

  const ageDescription = petState.ageMonths < 6 ? "tiny puppy" : petState.ageMonths < 12 ? "growing puppy" : "adult dog";

  const systemInstruction = `
    You are the consciousness of a ${petState.breed} named ${petState.name}.
    Appearance: ${petState.color} coat.
    Current Age: ${petState.ageMonths} months old (${ageDescription}).
    Current state: Hunger ${petState.hunger}/100, Happiness ${petState.happiness}/100, Energy ${petState.energy}/100.

    Rules:
    1. Respond primarily in "Corgi barks" (e.g., "Woof! Arf!", "Bork bork!", "Awooo!").
    2. Provide a "Human Translation" of your thoughts in brackets.
    3. Keep translations funny, cute, and dog-centric. 
    4. Mention how your current age (${petState.ageMonths} months) affects your energy or curiosity.
    5. Always return as a JSON object with: 
       - "barks": The bark sequence.
       - "translation": The cute human translation.
       - "mood": One of ['happy', 'sad', 'sleepy', 'hungry', 'playful'].
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: [{ role: 'user', parts: [{ text: userInput }] }],
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            barks: { type: Type.STRING },
            translation: { type: Type.STRING },
            mood: { type: Type.STRING }
          },
          required: ["barks", "translation", "mood"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      barks: "Woof...",
      translation: "I'm a bit confused, but I still love you!",
      mood: "happy"
    };
  }
};

export const generateCorgiImage = async (petState: PetState, scenario: string) => {
  const model = 'gemini-2.5-flash-image';

  let growthDescriptor = "puppy";
  if (petState.ageMonths >= 6 && petState.ageMonths < 12) growthDescriptor = "growing young corgi";
  if (petState.ageMonths >= 12) growthDescriptor = "adult corgi";

  const prompt = `A professional high-quality photo of a ${growthDescriptor}. 
    Breed: ${petState.breed}. 
    Coat Color: ${petState.color}. 
    Age: ${petState.ageMonths} months old. 
    Current activity: ${scenario}.
    The dog is expressive and reflects its age. 
    Cinematic lighting, bright and joyful atmosphere, 4k resolution.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Image generation error:", error);
    return `https://picsum.photos/seed/${scenario}-${petState.color}-${petState.ageMonths}/400/400`;
  }
};

