export interface PetState {
  name: string;
  breed: string;
  color: string;
  ageMonths: number;
  hunger: number;
  happiness: number;
  energy: number;
  level: number;
  xp: number;
  lastFed: number;
  isSleeping: boolean;
  adoptedAt: number;
  isAdopted: boolean;
  totalBondingTime: number; // in seconds
}

export interface CorgiMessage {
  role: 'user' | 'corgi';
  text: string;
  translation?: string;
  mood?: 'happy' | 'sad' | 'sleepy' | 'hungry' | 'playful';
}

export interface Activity {
  id: string;
  name: string;
  icon: string;
  hungerEffect: number;
  happinessEffect: number;
  energyEffect: number;
  xpGain: number;
  description: string;
}

export type ARInteractionState = 'IDLE' | 'HOVER' | 'PETTING' | 'OVERSTIMULATED';

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { PetState, CorgiMessage, Activity, ARInteractionState } from './types';
import { INITIAL_STATE, ACTIVITIES, MAX_STAT, XP_PER_LEVEL, BREEDS, COLORS, BELLY_HITBOX } from './constants';
import StatusBar from './components/StatusBar';
import { generateCorgiResponse } from './services/geminiService';

declare const Hands: any;
declare const Camera: any;

const App: React.FC = () => {
  const [pet, setPet] = useState<PetState>(() => {
    const saved = localStorage.getItem('corgi-breeder-v2');
    return saved ? JSON.parse(saved) : INITIAL_STATE;
  });

  // UI States
  const [isTyping, setIsTyping] = useState(false);
  const [messages, setMessages] = useState<CorgiMessage[]>([]);
  const [inputValue, setInputValue] = useState('');

  // AR States
  const [isARActive, setIsARActive] = useState(false);
  const [interactionState, setInteractionState] = useState<ARInteractionState>('IDLE');
  const [pettingIntensity, setPettingIntensity] = useState(0); // 0 to 1
  const [handPos, setHandPos] = useState<{ x: number, y: number } | null>(null);
  const [cameraError, setCameraError] = useState<string | null>(null);

  // Refs for logic
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const lastHandPos = useRef<{ x: number, y: number, time: number } | null>(null);
  const pettingStartTime = useRef<number | null>(null);
  const overstimulatedTime = useRef<number | null>(null);
  const handsRef = useRef<any>(null);

  // Persistence
  useEffect(() => {
    localStorage.setItem('corgi-breeder-v2', JSON.stringify(pet));
  }, [pet]);

  // Adoption logic
  const handleAdopt = (e: React.FormEvent) => {
    e.preventDefault();
    if (!pet.name.trim()) return;
    setPet(prev => ({ ...prev, isAdopted: true, adoptedAt: Date.now() }));
    setMessages([{ 
      role: 'corgi', 
      text: "Woof woof! (I'm so excited to be your new best friend!)", 
      translation: "Hello! Thank you for adopting me!",
      mood: 'happy' 
    }]);
  };

  // Stat Decay & Regen
  useEffect(() => {
    if (!pet.isAdopted) return;
    const interval = setInterval(() => {
      setPet(prev => {
        if (prev.isSleeping) {
          return {
            ...prev,
            energy: Math.min(MAX_STAT, prev.energy + 5),
            hunger: Math.max(0, prev.hunger - 0.2),
          };
        }
        return {
          ...prev,
          hunger: Math.max(0, prev.hunger - 0.1),
          happiness: Math.max(0, prev.happiness - 0.05),
          energy: Math.max(0, prev.energy - 0.08),
        };
      });
    }, 3000);
    return () => clearInterval(interval);
  }, [pet.isAdopted]);

  // MediaPipe Setup
  const setupMediaPipe = useCallback(() => {
    if (!videoRef.current) return;

    const hands = new Hands({
      locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/hands/${file}`
    });

    hands.setOptions({
      maxNumHands: 1,
      modelComplexity: 1,
      minDetectionConfidence: 0.5,
      minTrackingConfidence: 0.5
    });

    hands.onResults((results: any) => {
      if (results.multiHandLandmarks && results.multiHandLandmarks.length > 0) {
        const landmarks = results.multiHandLandmarks[0];
        // Index finger tip (8) or middle finger mcp (9)
        const point = landmarks[9];
        const currentX = point.x * (canvasRef.current?.width || 0);
        const currentY = point.y * (canvasRef.current?.height || 0);

        setHandPos({ x: currentX, y: currentY });
        handleInteractionLogic(currentX, currentY);
      } else {
        setHandPos(null);
        setInteractionState('IDLE');
        setPettingIntensity(0);
        pettingStartTime.current = null;
      }
    });

    const camera = new Camera(videoRef.current, {
      onFrame: async () => {
        await hands.send({ image: videoRef.current! });
      },
      width: 640,
      height: 480
    });

    camera.start().catch((err: any) => {
      setCameraError("Camera permission denied or not found.");
    });

    handsRef.current = hands;
  }, []);

  const handleInteractionLogic = (x: number, y: number) => {
    if (!canvasRef.current || overstimulatedTime.current && Date.now() - overstimulatedTime.current < 2000) return;

    const cw = canvasRef.current.width;
    const ch = canvasRef.current.height;
    const centerX = cw / 2;
    const centerY = ch / 2;

    // Hitbox detection
    const relX = x - centerX;
    const relY = y - centerY;

    const inHitbox = 
      relX >= BELLY_HITBOX.x && 
      relX <= BELLY_HITBOX.x + BELLY_HITBOX.width &&
      relY >= BELLY_HITBOX.y && 
      relY <= BELLY_HITBOX.y + BELLY_HITBOX.height;

    if (inHitbox) {
      const now = Date.now();
      if (lastHandPos.current) {
        const dx = x - lastHandPos.current.x;
        const dy = y - lastHandPos.current.y;
        const dt = now - lastHandPos.current.time;
        const speed = Math.sqrt(dx * dx + dy * dy) / dt;

        // Is it a rubbing motion?
        if (speed > 0.1 && speed < 3.0) {
          if (!pettingStartTime.current) pettingStartTime.current = now;
          const duration = now - pettingStartTime.current;

          if (duration > 300) {
            setInteractionState('PETTING');
            const intensity = Math.min(1, speed * 0.5);
            setPettingIntensity(intensity);

            // Apply rewards
            setPet(prev => ({
              ...prev,
              happiness: Math.min(MAX_STAT, prev.happiness + 0.1),
              xp: prev.xp + 0.05,
              totalBondingTime: prev.totalBondingTime + (dt / 1000)
            }));

            // Check for overstimulation
            if (duration > 8000 && intensity > 0.8) {
              setInteractionState('OVERSTIMULATED');
              overstimulatedTime.current = now;
              pettingStartTime.current = null;
            }
          } else {
            setInteractionState('HOVER');
          }
        } else {
          setInteractionState('HOVER');
        }
      }
      lastHandPos.current = { x, y, time: now };
    } else {
      setInteractionState('IDLE');
      setPettingIntensity(0);
      pettingStartTime.current = null;
    }
  };

  const toggleAR = () => {
    if (isARActive) {
      window.location.reload(); // Simplest way to clean up MediaPipe/Camera
    } else {
      setIsARActive(true);
      setupMediaPipe();
    }
  };

  const handleAction = async (activity: Activity) => {
    if (pet.isSleeping) return;

    setPet(prev => ({
      ...prev,
      hunger: Math.min(MAX_STAT, prev.hunger + activity.hungerEffect),
      happiness: Math.min(MAX_STAT, prev.happiness + activity.happinessEffect),
      energy: Math.max(0, prev.energy + activity.energyEffect),
      xp: prev.xp + activity.xpGain
    }));

    setIsTyping(true);
    const aiResp = await generateCorgiResponse(`I just ${activity.name.toLowerCase()} with you!`, pet, []);
    setIsTyping(false);

    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);
  };

  const handleChat = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim()) return;
    const msg = inputValue;
    setInputValue('');
    setMessages(prev => [...prev, { role: 'user', text: msg }]);
    setIsTyping(true);
    const aiResp = await generateCorgiResponse(msg, pet, []);
    setIsTyping(false);
    setMessages(prev => [...prev, {
      role: 'corgi',
      text: aiResp.barks,
      translation: aiResp.translation,
      mood: aiResp.mood
    }]);
  };

  // --- RENDERING COMPONENTS ---

  const CorgiSprite = ({ state, intensity }: { state: ARInteractionState, intensity: number }) => {
    // We use a responsive SVG system to animate the Corgi parts
    const isPetting = state === 'PETTING';
    const isHover = state === 'HOVER';
    const isOver = state === 'OVERSTIMULATED';

    // Calculate wag speed
    const wagClass = isPetting ? (intensity > 0.7 ? 'tail-wagging-fast' : 'tail-wagging') : (isHover ? 'tail-wagging' : '');

    return (
      <svg viewBox="0 0 400 400" className={`w-full h-full transition-all duration-500 transform ${isPetting ? 'rotate-[-20deg] scale-110' : ''}`}>
        <defs>
          <filter id="shadow" x="-20%" y="-20%" width="140%" height="140%">
            <feGaussianBlur in="SourceAlpha" stdDeviation="3" />
            <feOffset dx="2" dy="2" result="offsetblur" />
            <feComponentTransfer>
              <feFuncA type="linear" slope="0.3" />
            </feComponentTransfer>
            <feMerge>
              <feMergeNode />
              <feMergeNode in="SourceGraphic" />
            </feMerge>
          </filter>
        </defs>

        {/* Shadow */}
        <ellipse cx="200" cy="340" rx="100" ry="20" fill="rgba(0,0,0,0.1)" />

        {/* Tail */}
        <g className={wagClass}>
           <path d="M110,250 Q80,230 70,250 T60,280" stroke="#C88C4B" strokeWidth="25" strokeLinecap="round" fill="none" />
        </g>

        {/* Body */}
        <path d="M150,220 Q200,180 300,220 Q350,260 300,320 Q200,350 150,320 Z" fill="#E6A15C" filter="url(#shadow)" />
        <path d="M170,240 Q210,210 280,240 Q310,270 280,310 Q210,330 170,310 Z" fill="#FFFFFF" />

        {/* Legs */}
        <rect x="160" y="310" width="30" height="40" rx="15" fill="#E6A15C" />
        <rect x="260" y="310" width="30" height="40" rx="15" fill="#E6A15C" />

        {/* Head */}
        <g className={`transition-transform duration-300 ${isPetting ? 'translate-y-[-10px] rotate-[10deg]' : ''}`}>
          {/* Ears */}
          <path d="M130,170 L110,100 L160,140 Z" fill="#E6A15C" />
          <path d="M220,170 L240,100 L190,140 Z" fill="#E6A15C" />

          <circle cx="175" cy="200" r="70" fill="#E6A15C" filter="url(#shadow)" />
          <path d="M175,210 Q140,240 175,270 Q210,240 175,210" fill="#FFFFFF" />

          {/* Eyes */}
          <circle cx="150" cy="180" r="5" fill="#333" />
          <circle cx="200" cy="180" r="5" fill="#333" />
          {isPetting && <path d="M140,185 Q150,175 160,185 M190,185 Q200,175 210,185" fill="none" stroke="#333" strokeWidth="2" />}

          {/* Nose & Mouth */}
          <circle cx="175" cy="220" r="7" fill="#222" />
          {isPetting ? (
            <path d="M165,240 Q175,260 185,240" fill="#FF80AB" className="tongue-panting" />
          ) : (
            <path d="M165,235 Q175,245 185,235" fill="none" stroke="#333" strokeWidth="2" />
          )}
        </g>
      </svg>
    );
  };

  if (!pet.isAdopted) {
    return (
      <div className="min-h-screen bg-[#fdf6e3] flex flex-col items-center justify-center p-6 bg-[url('https://www.transparenttextures.com/patterns/paws.png')]">
        <div className="max-w-md w-full bg-white rounded-[3rem] shadow-2xl p-10 border-[12px] border-orange-100 animate-in fade-in slide-in-from-bottom-10 duration-700">
          <div className="text-center mb-8">
             <div className="w-32 h-32 mx-auto mb-6 bg-orange-50 rounded-full flex items-center justify-center border-4 border-orange-100">
                <CorgiSprite state="IDLE" intensity={0} />
             </div>
             <h1 className="text-4xl font-brand text-orange-600 mb-2">CorgiLife</h1>
             <p className="text-stone-500 font-bold">Your journey as a breeder begins...</p>
          </div>
          <form onSubmit={handleAdopt} className="space-y-6">
            <div>
              <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">Choose a Breed</label>
              <select value={pet.breed} onChange={(e) => setPet({...pet, breed: e.target.value})} className="w-full mt-1 p-4 rounded-2xl bg-orange-50/50 border-2 border-orange-100 font-bold text-stone-700">
                {BREEDS.map(b => <option key={b} value={b}>{b}</option>)}
              </select>
            </div>
            <div>
              <label className="text-xs font-black text-stone-400 uppercase tracking-widest px-2">Dog's Name</label>
              <input type="text" value={pet.name} onChange={(e) => setPet({...pet, name: e.target.value})} placeholder="e.g. Biscuit" className="w-full mt-1 p-5 rounded-2xl bg-stone-50 border-2 border-stone-200 font-brand text-2xl text-stone-800 placeholder:text-stone-300 text-center focus:border-orange-400 outline-none" required />
            </div>
            <button type="submit" className="w-full py-5 bg-orange-500 hover:bg-orange-600 text-white rounded-2xl font-brand text-2xl shadow-xl hover:shadow-orange-300/60 transition-all transform hover:-translate-y-1">
              Start Raising ✨
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen w-screen overflow-hidden flex flex-col bg-[#fdf6e3] relative">
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/paws.png')]"></div>

      {/* Interactive Render Layer */}
      <div className="flex-1 relative overflow-hidden">
        {isARActive && (
          <div id="video-container" className="absolute inset-0 bg-black">
            <video ref={videoRef} className="w-full h-full object-cover" />
            <canvas ref={canvasRef} id="interactive-canvas" className="hidden" />
          </div>
        )}

        <div className={`absolute inset-0 transition-all duration-700 ${isARActive ? 'bg-[#fdf6e3]/30 backdrop-blur-sm' : 'bg-transparent'}`}>
           <div className="h-full w-full flex items-center justify-center relative">
              {/* Hitbox visualizer (dev only, but helpful for user to know where to pet) */}
              {isARActive && interactionState === 'IDLE' && (
                <div className="absolute w-40 h-32 border-4 border-dashed border-white/40 rounded-[2rem] animate-pulse flex items-center justify-center">
                  <span className="text-white/60 font-black text-xs uppercase tracking-widest">Pet Belly Here</span>
                </div>
              )}

              <div className="w-[80vw] h-[80vw] max-w-[500px] max-h-[500px] z-20">
                 <CorgiSprite state={interactionState} intensity={pettingIntensity} />
              </div>

              {/* Hand Glow Indicator */}
              {handPos && (
                <div 
                  className="hand-indicator"
                  style={{ 
                    left: `calc(100% - ${handPos.x}px)`, // Adjust for mirrored cam
                    top: `${handPos.y}px`,
                    transform: 'translate(-50%, -50%)'
                  }}
                />
              )}

              {/* Status Indicator */}
              {interactionState === 'PETTING' && (
                <div className="absolute top-1/4 left-1/2 -translate-x-1/2 text-7xl animate-bounce z-50">❤️</div>
              )}
              {interactionState === 'OVERSTIMULATED' && (
                <div className="absolute top-1/4 left-1/2 -translate-x-1/2 text-7xl animate-ping z-50">💢</div>
              )}
           </div>
        </div>
      </div>

      {/* Floating UI Overlays */}
      <div className="absolute top-0 left-0 w-full p-6 z-50 flex justify-between items-start">
        <div className="space-y-4 max-w-xs">
           <div className="bg-white/90 backdrop-blur-md p-6 rounded-[2.5rem] shadow-xl border-4 border-orange-100 floating-ui">
              <h1 className="font-brand text-3xl text-orange-600 mb-4">{pet.name}</h1>
              <div className="space-y-4">
                 <StatusBar label="Happiness" value={pet.happiness} color="bg-pink-400" icon="💖" />
                 <StatusBar label="Energy" value={pet.energy} color="bg-cyan-400" icon="⚡" />
              </div>
           </div>

           {cameraError && (
             <div className="bg-red-500 text-white p-4 rounded-2xl text-xs font-bold shadow-lg animate-bounce">
                ⚠️ {cameraError}
             </div>
           )}
        </div>

        <div className="flex flex-col items-end gap-4">
           <button 
             onClick={toggleAR}
             className={`p-5 rounded-[2.5rem] font-black text-sm uppercase tracking-widest transition-all shadow-xl border-4 flex items-center gap-3 ${
               isARActive ? 'bg-red-500 text-white border-red-200' : 'bg-white text-orange-600 border-orange-100 hover:scale-105'
             }`}
           >
             <span className="text-3xl">{isARActive ? '⏹️' : '📸'}</span>
             {isARActive ? 'Stop Camera' : 'Enter AR Portal'}
           </button>

           <div className="bg-white/90 backdrop-blur-md px-6 py-4 rounded-[2rem] shadow-xl border-4 border-orange-100 text-center">
              <div className="text-xs uppercase font-black text-stone-400 tracking-tighter">Level</div>
              <div className="text-3xl font-brand text-orange-500">{pet.level}</div>
           </div>
        </div>
      </div>

      {/* Bottom Interface */}
      <div className={`transition-all duration-500 ${isARActive ? 'h-0 opacity-0 translate-y-20' : 'h-[40vh] opacity-100'}`}>
         <div className="h-full w-full max-w-6xl mx-auto p-6 flex gap-6">
            {/* Actions Panel */}
            <div className="flex-1 grid grid-cols-2 gap-4">
               {ACTIVITIES.map(act => (
                 <button key={act.id} onClick={() => handleAction(act)} className="bg-white p-6 rounded-[2.5rem] shadow-lg border-b-[8px] border-stone-100 hover:-translate-y-1 transition-all group flex flex-col items-center justify-center">
                   <span className="text-4xl group-hover:scale-125 transition-transform mb-2">{act.icon}</span>
                   <span className="text-[10px] font-black uppercase text-stone-400">{act.name}</span>
                 </button>
               ))}
            </div>

            {/* Chat Panel */}
            <div className="flex-[1.5] bg-white rounded-[3rem] shadow-2xl flex flex-col overflow-hidden border-4 border-orange-50">
               <div className="p-4 border-b border-orange-50 bg-orange-50/20 flex items-center gap-4">
                  <div className="w-10 h-10 rounded-xl bg-orange-300 flex items-center justify-center text-xl">🐕</div>
                  <span className="font-brand text-stone-700">Bark Diary</span>
               </div>
               <div className="flex-1 p-6 overflow-y-auto space-y-4 scrollbar-hide">
                  {messages.length === 0 && <p className="text-stone-300 italic text-center mt-10">Start a conversation with your friend...</p>}
                  {messages.map((m, i) => (
                    <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                       <div className={`p-4 rounded-2xl max-w-[80%] ${m.role === 'user' ? 'bg-orange-500 text-white rounded-tr-none' : 'bg-stone-50 text-stone-800 rounded-tl-none border border-stone-200'}`}>
                          <p className="font-bold text-sm">{m.text}</p>
                          {m.translation && <p className="text-[10px] mt-2 pt-2 border-t border-black/10 opacity-70 italic">"{m.translation}"</p>}
                       </div>
                    </div>
                  ))}
                  {isTyping && <div className="text-xs text-orange-400 font-bold animate-pulse">Dog is thinking...</div>}
               </div>
               <form onSubmit={handleChat} className="p-4 bg-stone-50 border-t border-orange-50 flex gap-2">
                  <input type="text" value={inputValue} onChange={e => setInputValue(e.target.value)} placeholder="Say something..." className="flex-1 bg-white p-3 rounded-full border border-stone-200 focus:outline-none focus:border-orange-400 font-bold text-sm" />
                  <button type="submit" className="bg-orange-500 text-white p-3 rounded-full shadow-lg">🐾</button>
               </form>
            </div>
         </div>
      </div>

      {/* AR Instruction Toast */}
      {isARActive && interactionState === 'IDLE' && (
        <div className="absolute bottom-10 left-1/2 -translate-x-1/2 bg-white/90 px-8 py-4 rounded-full shadow-2xl border-4 border-orange-100 z-50 animate-bounce">
           <p className="font-brand text-orange-600 text-lg">Wiggle your hand over the belly to rub it! 👋</p>
        </div>
      )}
    </div>
  );
};

