          <form onSubmit={handleSendMessage} className="p-8 bg-white border-t-4 border-orange-50">
            <div className="flex gap-4 items-center bg-stone-50 p-3 rounded-[2.5rem] border-4 border-stone-100 focus-within:border-orange-400 shadow-inner">
              <input 
                type="text" 
                value={inputValue} 
                onChange={(e) => setInputValue(e.target.value)}
                placeholder={`Talk to ${pet.name}...`}
                className="flex-1 p-4 bg-transparent border-none focus:outline-none font-bold text-xl text-stone-700"
              />
              <button 
                type="submit"
                className="bg-orange-500 text-white w-16 h-16 rounded-[1.5rem] flex items-center justify-center font-bold shadow-2xl hover:scale-105 active:scale-90 transition-all"
              >
                🐾
              </button>
            </div>
          </form>
        </div>
      </main>

      <footer className="mt-20 w-full max-w-6xl grid grid-cols-2 md:grid-cols-4 gap-6 pb-20 relative z-10">
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white">
            <span className="block text-4xl mb-2">🎂</span>
            <span className="text-xs font-black text-stone-400 uppercase tracking-widest">Growth</span>
            <p className="font-brand text-2xl text-stone-700">{pet.ageMonths} Months</p>
         </div>
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white">
            <span className="block text-4xl mb-2">🧬</span>
            <span className="text-xs font-black text-stone-400 uppercase tracking-widest">Breed</span>
            <p className="font-brand text-2xl text-stone-700">{pet.breed.split(' ')[0]}</p>
         </div>
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white">
            <span className="block text-4xl mb-2">🏡</span>
            <span className="text-xs font-black text-stone-400 uppercase tracking-widest">Bonded</span>
            <p className="font-brand text-2xl text-stone-700">{bondedTime}</p>
         </div>
         <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2.5rem] text-center shadow-xl border-2 border-white">
            <span className="block text-4xl mb-2">✨</span>
            <span className="text-xs font-black text-stone-400 uppercase tracking-widest">Status</span>
            <p className="font-brand text-2xl text-green-500">THRIVING</p>
         </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { GoogleGenAI, Type } from "@google/genai";

// --- Types ---
interface PetState {
  name: string;
  breed: string;
  color: string;
  ageMonths: number;
  hunger: number;
  happiness: number;
  energy: number;
  level: number;
  xp: number;
  lastFed: number;
  isSleeping: boolean;
  adoptedAt: number;
  isAdopted: boolean;
}

interface CorgiMessage {
  role: 'user' | 'corgi';
  text: string;
  translation?: string;
  mood?: 'happy' | 'sad' | 'sleepy' | 'hungry' | 'playful';
}

interface Activity {
  id: string;
  name: string;
  icon: string;
  hungerEffect: number;
  happinessEffect: number;
  energyEffect: number;
  xpGain: number;
  description: string;
}

// --- Constants ---
const INITIAL_STATE: PetState = {
  name: '',
  breed: 'Pembroke Welsh Corgi',
  color: 'Red & White',
  ageMonths: 3,
  hunger: 80,
  happiness: 80,
  energy: 100,
  level: 1,
  xp: 0,
  lastFed: Date.now(),
  isSleeping: false,
  adoptedAt: Date.now(),
  isAdopted: false,
};

const BREEDS = ['Pembroke Welsh Corgi', 'Cardigan Welsh Corgi', 'Fluffy Corgi (Long-haired)'];
const COLORS = ['Red & White', 'Tri-color', 'Sable', 'Brindle', 'Blue Merle', 'Black & Tan'];
const MAX_STAT = 100;
const XP_PER_LEVEL = 100;
const EAT_SOUND_URL = 'https://assets.mixkit.co/active_storage/sfx/554/554-preview.mp3';

const ACTIVITIES: Activity[] = [
  { id: 'feed', name: 'Give Treat', icon: '🥣', hungerEffect: 20, happinessEffect: 5, energyEffect: 0, xpGain: 15, description: 'A tasty treat!' },
  { id: 'play', name: 'Fetch Ball', icon: '🎾', hungerEffect: -15, happinessEffect: 25, energyEffect: -20, xpGain: 25, description: 'Play time!' },
  { id: 'walk', name: 'Go for Walk', icon: '🌳', hungerEffect: -10, happinessEffect: 15, energyEffect: -30, xpGain: 35, description: 'Exploring!' },
  { id: 'belly-rub', name: 'Belly Rub', icon: '🖐️', hungerEffect: 0, happinessEffect: 10, energyEffect: 0, xpGain: 10, description: 'Pure bliss.' }
];

// --- AI Services ---
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY! });

const generateCorgiResponse = async (userInput: string, pet: PetState) => {
  const ai = getAI();
  const ageDesc = pet.ageMonths < 6 ? "puppy" : pet.ageMonths < 12 ? "young dog" : "adult";
  const systemInstruction = `You are a ${pet.breed} named ${pet.name}. Current age: ${pet.ageMonths} months (${ageDesc}). Mood: ${pet.happiness > 70 ? 'joyful' : 'neutral'}. Return JSON: { "barks": "Bark string", "translation": "Funny dog thought", "mood": "happy|sad|sleepy|hungry|playful" }.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [{ role: 'user', parts: [{ text: userInput }] }],
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            barks: { type: Type.STRING },
            translation: { type: Type.STRING },
            mood: { type: Type.STRING }
          },
          required: ["barks", "translation", "mood"]
        }
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (e) {
    return { barks: "Woof!", translation: "I'm just happy to see you!", mood: "happy" };
  }
};

const generateCorgiImage = async (pet: PetState, scenario: string) => {
  const ai = getAI();
  const growth = pet.ageMonths < 6 ? "tiny puppy" : pet.ageMonths < 12 ? "young dog" : "full grown dog";
  const prompt = `A professional 4k photo of a ${growth} ${pet.breed} with ${pet.color} coat. Scenario: ${scenario}. High quality, cinematic lighting.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ text: prompt }] },
      config: { imageConfig: { aspectRatio: "1:1" } }
    });
    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return part ? `data:image/png;base64,${part.inlineData.data}` : null;
  } catch (e) {
    return `https://picsum.photos/seed/${pet.name}-${scenario}/500/500`;
  }
};

// --- Components ---
const StatusBar: React.FC<{ label: string; value: number; color: string; icon: string }> = ({ label, value, color, icon }) => (
  <div className="w-full">
    <div className="flex justify-between text-[10px] font-black text-stone-400 uppercase tracking-widest mb-1">
      <span>{icon} {label}</span>
      <span>{Math.round(value)}%</span>
    </div>
    <div className="h-2.5 bg-stone-100 rounded-full overflow-hidden shadow-inner border border-stone-200">
      <div className={`h-full transition-all duration-1000 ${color}`} style={{ width: `${Math.min(100, Math.max(0, value))}%` }} />
    </div>
  </div>
);

const App: React.FC = () => {
  const [pet, setPet] = useState<PetState>(() => {
    const saved = localStorage.getItem('corgi-v2');
    return saved ? JSON.parse(saved) : INITIAL_STATE;
  });
  const [messages, setMessages] = useState<CorgiMessage[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [petImage, setPetImage] = useState<string>('');
  const [isBusy, setIsBusy] = useState(false);
  const [showLevelUp, setShowLevelUp] = useState(false);
  const [currentTime, setCurrentTime] = useState(Date.now());

  const chatEndRef = useRef<HTMLDivElement>(null);
  const eatAudio = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    localStorage.setItem('corgi-v2', JSON.stringify(pet));
  }, [pet]);

  useEffect(() => {
    const clock = setInterval(() => setCurrentTime(Date.now()), 10000);
    const decay = setInterval(() => {
      if (!pet.isAdopted) return;
      setPet(prev => ({
        ...prev,
        hunger: Math.max(0, prev.hunger - (prev.isSleeping ? 0.05 : 0.2)),
        happiness: Math.max(0, prev.happiness - 0.1),
        energy: prev.isSleeping ? Math.min(100, prev.energy + 1.5) : Math.max(0, prev.energy - 0.15),
        isSleeping: prev.isSleeping && prev.energy < 100
      }));
    }, 5000);
    return () => { clearInterval(clock); clearInterval(decay); };
  }, [pet.isAdopted]);

  useEffect(() => {
    if (pet.isAdopted && !petImage) refreshImage('happily sitting');
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, pet.isAdopted]);

  const refreshImage = async (context: string) => {
    setIsBusy(true);
    const img = await generateCorgiImage(pet, context);
    if (img) setPetImage(img);
    setIsBusy(false);
  };

  const performAction = async (activity: Activity) => {
    if (pet.isSleeping || isBusy) return;

    // Play ONLY the eat sound for treat action
    if (activity.id === 'feed') {
      if (!eatAudio.current) eatAudio.current = new Audio(EAT_SOUND_URL);
      eatAudio.current.currentTime = 0;
      eatAudio.current.play().catch(() => {});
    }

    const nextXP = pet.xp + activity.xpGain;
    const didLevel = nextXP >= XP_PER_LEVEL;

    const updated = {
      ...pet,
      hunger: Math.min(100, pet.hunger + activity.hungerEffect),
      happiness: Math.min(100, pet.happiness + activity.happinessEffect),
      energy: Math.max(0, pet.energy + activity.energyEffect),
      xp: didLevel ? nextXP - XP_PER_LEVEL : nextXP,
      level: didLevel ? pet.level + 1 : pet.level,
      ageMonths: didLevel ? pet.ageMonths + 1 : pet.ageMonths
    };

    setPet(updated);
    if (didLevel) {
      setShowLevelUp(true);
      setTimeout(() => setShowLevelUp(false), 3000);
    }

    const aiResp = await generateCorgiResponse(`I just did ${activity.name}!`, updated);
    setMessages(prev => [...prev, { role: 'corgi', ...aiResp }]);
    if (Math.random() > 0.5 || didLevel) refreshImage(activity.name.toLowerCase());
  };

  const handleChat = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim() || isBusy) return;
    const text = inputValue;
    setInputValue('');
    setMessages(prev => [...prev, { role: 'user', text }]);
    const aiResp = await generateCorgiResponse(text, pet);
    setMessages(prev => [...prev, { role: 'corgi', ...aiResp }]);
  };

  const bondedDisplay = useMemo(() => {
    const diff = currentTime - pet.adoptedAt;
    const m = Math.floor(diff / 60000);
    const h = Math.floor(m / 60);
    const d = Math.floor(h / 24);
    if (d > 0) return `${d} day${d === 1 ? '' : 's'}`;
    if (h > 0) return `${h} hour${h === 1 ? '' : 's'}`;
    return `${m} min${m === 1 ? '' : 's'}`;
  }, [currentTime, pet.adoptedAt]);

  if (!pet.isAdopted) {
    return (
      <div className="min-h-screen bg-[#fdf6e3] flex items-center justify-center p-6 bg-[url('https://www.transparenttextures.com/patterns/paws.png')]">
        <div className="max-w-lg w-full bg-white rounded-[3rem] shadow-2xl p-10 border-8 border-orange-100 animate-in zoom-in duration-500">
          <div className="text-center mb-8">
            <span className="text-6xl mb-4 block">🦴</span>
            <h1 className="text-4xl font-brand text-orange-600 mb-2">Corgi Breeder</h1>
            <p className="text-stone-400 font-bold uppercase text-xs tracking-widest">Create Your Lifelong Friend</p>
          </div>
          <div className="space-y-6">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-stone-400 uppercase ml-2">Breed</label>
              <select className="w-full p-4 rounded-2xl bg-stone-50 border-2 border-stone-100 font-bold text-stone-700" value={pet.breed} onChange={e => setPet({...pet, breed: e.target.value})}>
                {BREEDS.map(b => <option key={b}>{b}</option>)}
              </select>
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-stone-400 uppercase ml-2">Coat Color</label>
              <div className="grid grid-cols-3 gap-2">
                {COLORS.map(c => (
                  <button key={c} onClick={() => setPet({...pet, color: c})} className={`p-2 text-[9px] font-black rounded-xl border-2 transition-all ${pet.color === c ? 'bg-orange-500 text-white border-orange-600' : 'bg-white text-stone-400 border-stone-100'}`}>{c}</button>
                ))}
              </div>
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-stone-400 uppercase ml-2">Starting Name</label>
              <input type="text" className="w-full p-4 rounded-2xl bg-stone-50 border-2 border-stone-100 font-brand text-xl text-center" placeholder="Bubbles..." value={pet.name} onChange={e => setPet({...pet, name: e.target.value})} />
            </div>
            <button onClick={() => setPet({...pet, isAdopted: true, adoptedAt: Date.now()})} disabled={!pet.name} className="w-full py-5 bg-orange-500 hover:bg-orange-600 text-white rounded-2xl font-brand text-xl shadow-xl transition-all disabled:opacity-30">Adopt My Corgi! ✨</button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#fdf6e3] text-stone-800 flex flex-col items-center bg-[url('https://www.transparenttextures.com/patterns/paws.png')] p-4 md:p-8">
      <div className="w-full max-w-6xl flex flex-col lg:grid lg:grid-cols-2 gap-8 items-start">

        {/* Visual & Stats Column */}
        <div className="w-full space-y-6">
          <div className="relative aspect-square bg-white rounded-[3.5rem] shadow-2xl border-[12px] border-white overflow-hidden flex items-center justify-center">
            {isBusy && (
              <div className="absolute inset-0 z-10 bg-white/60 backdrop-blur-sm flex items-center justify-center">
                <div className="animate-spin text-4xl">📸</div>
              </div>
            )}
            {showLevelUp && (
              <div className="absolute inset-0 z-20 bg-orange-500/30 backdrop-blur-md flex flex-col items-center justify-center animate-in fade-in zoom-in duration-300">
                <div className="text-8xl mb-4 animate-bounce">🎂</div>
                <h2 className="text-5xl font-brand text-white drop-shadow-lg">LEVEL UP!</h2>
              </div>
            )}
            <img src={petImage || `https://picsum.photos/seed/${pet.name}/600/600`} className={`w-full h-full object-cover transition-all duration-700 ${pet.isSleeping ? 'grayscale brightness-50' : ''}`} alt={pet.name} />
            {pet.isSleeping && <div className="absolute top-10 right-10 text-6xl animate-pulse">💤</div>}
          </div>

          <div className="bg-white p-8 rounded-[2.5rem] shadow-xl border-4 border-orange-50 space-y-6">
            <div className="flex justify-between items-end">
              <div>
                <h1 className="font-brand text-3xl text-orange-600">{pet.name}</h1>
                <p className="text-xs font-black text-stone-400 uppercase tracking-widest">{pet.ageMonths} Months • {pet.breed}</p>
              </div>
              <div className="text-right">
                <span className="text-[10px] font-black text-stone-400 block mb-1">LVL {pet.level}</span>
                <div className="w-24 h-2 bg-stone-100 rounded-full overflow-hidden border border-stone-200">
                  <div className="h-full bg-orange-400" style={{ width: `${(pet.xp / XP_PER_LEVEL) * 100}%` }} />
                </div>
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <StatusBar label="Hunger" value={pet.hunger} color="bg-amber-400" icon="🥣" />
              <StatusBar label="Mood" value={pet.happiness} color="bg-pink-400" icon="💖" />
              <StatusBar label="Energy" value={pet.energy} color="bg-cyan-400" icon="⚡" />
            </div>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
            {ACTIVITIES.map(act => (
              <button key={act.id} onClick={() => performAction(act)} disabled={pet.isSleeping || isBusy} className="bg-white p-5 rounded-[2rem] shadow-lg border-b-8 border-stone-100 hover:-translate-y-1 active:translate-y-1 transition-all flex flex-col items-center group disabled:opacity-30">
                <span className="text-4xl mb-2 group-hover:scale-110 transition-transform">{act.icon}</span>
                <span className="text-[10px] font-black text-stone-500 uppercase">{act.name}</span>
              </button>
            ))}
            <button onClick={() => setPet({...pet, isSleeping: !pet.isSleeping})} className={`col-span-2 sm:col-span-4 py-5 rounded-[2rem] font-brand text-xl shadow-xl transition-all flex items-center justify-center gap-4 ${pet.isSleeping ? 'bg-indigo-600 text-white' : 'bg-white text-stone-700 hover:bg-indigo-50 border-b-8 border-stone-100'}`}>
              {pet.isSleeping ? '☀️ Wake Up' : '🌙 Nap Time'}
            </button>
          </div>
        </div>

        {/* Bark Translator Column */}
        <div className="w-full bg-white rounded-[3.5rem] shadow-2xl border-8 border-orange-50 flex flex-col h-[600px] lg:h-[840px] overflow-hidden">
          <div className="p-6 bg-orange-50/50 border-b-2 border-orange-100 flex items-center gap-4">
            <div className="w-12 h-12 bg-orange-200 rounded-2xl flex items-center justify-center text-2xl">🗣️</div>
            <div>
              <h2 className="font-brand text-xl text-stone-700">Bark Translator</h2>
              <p className="text-[9px] font-black text-orange-400 uppercase animate-pulse">Live Translation Active</p>
            </div>
          </div>
          <div className="flex-1 overflow-y-auto p-6 space-y-6 scrollbar-hide">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
                <div className={`max-w-[85%] p-5 rounded-[1.8rem] shadow-md ${m.role === 'user' ? 'bg-orange-500 text-white rounded-tr-none' : 'bg-stone-50 text-stone-800 rounded-tl-none border border-stone-100'}`}>
                  <p className="font-bold text-lg">{m.text}</p>
                  {m.translation && (
                    <div className="mt-3 pt-3 border-t border-black/5 text-sm italic opacity-70">
                      "{m.translation}"
                    </div>
                  )}
                </div>
              </div>
            ))}
            <div ref={chatEndRef} />
          </div>
          <form onSubmit={handleChat} className="p-6 bg-stone-50/50 border-t-2 border-orange-100">
            <div className="flex gap-2 bg-white p-2 rounded-full border-2 border-stone-200 focus-within:border-orange-400 transition-all shadow-inner">
              <input type="text" className="flex-1 px-4 py-2 bg-transparent outline-none font-bold text-stone-600" placeholder={`Talk to ${pet.name}...`} value={inputValue} onChange={e => setInputValue(e.target.value)} />
              <button type="submit" className="w-12 h-12 bg-orange-500 text-white rounded-full flex items-center justify-center shadow-lg hover:scale-105 active:scale-95 transition-all">🐾</button>
            </div>
          </form>
        </div>
      </div>

      <footer className="w-full max-w-6xl mt-10 grid grid-cols-2 md:grid-cols-4 gap-4 pb-10">
        <div className="bg-white/60 p-5 rounded-[2rem] text-center shadow-sm border border-white">
          <span className="text-[9px] font-black text-stone-400 uppercase block tracking-widest">Bonded</span>
          <p className="font-brand text-xl text-orange-600">{bondedDisplay}</p>
        </div>
        <div className="bg-white/60 p-5 rounded-[2rem] text-center shadow-sm border border-white">
          <span className="text-[9px] font-black text-stone-400 uppercase block tracking-widest">Growth</span>
          <p className="font-brand text-xl text-stone-700">{pet.ageMonths} Mos</p>
        </div>
        <div className="bg-white/60 p-5 rounded-[2rem] text-center shadow-sm border border-white">
          <span className="text-[9px] font-black text-stone-400 uppercase block tracking-widest">Breed</span>
          <p className="font-brand text-xl text-stone-700">{pet.breed.split(' ')[0]}</p>
        </div>
        <div className="bg-white/60 p-5 rounded-[2rem] text-center shadow-sm border border-white">
          <span className="text-[9px] font-black text-stone-400 uppercase block tracking-widest">Status</span>
          <p className="font-brand text-xl text-green-500">THRIVING</p>
        </div>
      </footer>
    </div>
  );
};

